        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.PrintWriter;
import java.util.Comparator;
import java.util.PriorityQueue;
import java.util.Vector;

class Computer {
	long power, cost;
	public Computer() {
		power = 0;
		cost = 0;
	}
	public Computer(long power, long cost) {
		this.power = power;
		this.cost = cost;
	}

	public String toString() {
		return "(" + power + ", " + cost + ")";
	}
}

class ComparatorComputers implements Comparator<Computer> {
	public int compare(Computer nr1, Computer nr2) {
		return Long.compare(nr1.power, nr2.power);
	}
}

public class Crypto {
	public static void main(String[] args) {

		// MinHeap-ul pentru calculatoare
		PriorityQueue<Computer> computers = 
			new PriorityQueue<Computer>(10, new ComparatorComputers());
		try {
			// Citirea datelor din fisier
			BufferedReader br = new BufferedReader(new FileReader("crypto.in"));
			PrintWriter output = new PrintWriter(new File("crypto.out"));

			String[] nb = br.readLine().split(" ");
			Long N = Long.parseLong(nb[0]);
			Long B = Long.parseLong(nb[1]);

			for (long i = 0; i < N; i++) {
				String[] pc = br.readLine().split(" ");
				Long P = Long.parseLong(pc[0]);
				Long C = Long.parseLong(pc[1]);
				computers.add(new Computer(P, C));
			}

			// Algorithm starts here
			while (true) {

				//Vectorul de calculatoare ce trebuie upgradate;
				Vector<Computer> toBeUpgraded = new Vector<>();

				Computer minComputer = computers.poll();
				toBeUpgraded.add(minComputer);
				Computer nextMinComputer = computers.poll();

				// Calcularea costului de upgrade a calculatoarelor din toBeUpgraded
				int partialCost = 0;
				partialCost += minComputer.cost;

				// Adaugarea calculatoarelor cu puterea cea mai mica in vector
				while (minComputer.power == nextMinComputer.power) {
					toBeUpgraded.add(nextMinComputer);
					partialCost += nextMinComputer.cost;
					nextMinComputer = computers.poll();
					if (nextMinComputer == null) {
						nextMinComputer = toBeUpgraded.firstElement();
						partialCost += nextMinComputer.cost;
						// Adaugarea se incheie
						break;
					}
				}
				computers.add(nextMinComputer);

				/*Verific daca calculatoarele ce trebuie upgradate sunt, de fapt, 
				 toate calculatoarele. Daca da, afisez old_power + B / (costul total de upgrade)
				 pentru a nu mai itera degeaba prin vector*/
				if (nextMinComputer.power != toBeUpgraded.firstElement().power) {
					long diff = nextMinComputer.power - toBeUpgraded.firstElement().power;
					// Daca costul de upgrade se incadreaza in buget, upgradez cu diferenta
					// In caz contrar, afisez old_power + B / (costul total de upgrade)
					if (partialCost * diff <= B) {
						B -= partialCost * diff;
						for (Computer c : toBeUpgraded) {
							c.power += diff;
						}
					} else {
						diff = B / partialCost;
						output.printf("%d\n", toBeUpgraded.firstElement().power + diff);
						output.close();
						//Algoritmul se incheie.
						break;
					}
				} else {
					long diff = B / partialCost;
					output.printf("%d\n", toBeUpgraded.firstElement().power + diff);
					output.close();
					// Algoritmul se incheie.
					break;
				}
				// Adauga calculatoarele upgradate inapoi in MinHeap
				while (!toBeUpgraded.isEmpty()) {
					computers.add(toBeUpgraded.firstElement());
					toBeUpgraded.remove(toBeUpgraded.firstElement());
				}
			}
			output.printf("%d\n", computers.peek().power);
			output.close();
		} catch (Exception e) {
			e.printStackTrace();
		}
	}
}
        ```

