        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;

class Pc implements Comparable<Pc> {
	private int p;
	private int u;

	public Pc(int p, int u) {
		this.p = p;
		this.u = u;
	}

	public Pc() {

	}

	public int getP() {
		return p;
	}

	public int getU() {
		return u;
	}

	public void incrementProd() {
		this.p++;
	}



	@Override
	public int compareTo(Pc o) {
		if (this.getP() > o.getP()) {
			return 1;
		} else if (this.getP() < o.getP()) {
			return -1;
		} else {
			return 0;
		}
	}
}


public class Crypto {


	public static void main(String[] args) throws IOException {
		ArrayList<Pc> units = new ArrayList<Pc>();
		int Buget, N;

		BufferedReader reader = new BufferedReader(new FileReader("crypto.in"));
		// citim n si buget
		String[] input = reader.readLine().split(String.valueOf(' '), 2);
		N = Integer.parseInt(input[0]);
		Buget = Integer.parseInt(input[1]);
		// citim perechea pc
		for (int i = 0; i < N; i++) {
			input = reader.readLine().split(String.valueOf(' '), 2);
			units.add(new Pc(Integer.parseInt(input[0]), Integer.parseInt(input[1])));
		}


		Collections.sort(units);

		int bugetUp = 0;
		Integer minim = units.get(0).getP();
		for (int i = 0; i < N - 1; i++) {
			bugetUp += units.get(i).getU();
			// elementul urmator e diferit => se poate face upgrade
			if (units.get(i + 1).getP() != units.get(i).getP()) {
				while (bugetUp <= Buget && minim != units.get(i + 1).getP()) {
					Buget -= bugetUp;
					minim++;
				}
				if (bugetUp > Buget) {
					break;
				}
			}
		}

		//upgrade uri cat este posibil
		while (bugetUp <= Buget) {
			if (minim == units.get(N - 1).getP()) {
				//calcul pt ultimul element
				bugetUp += units.get(N - 1).getU();
			}
			minim++;
			Buget -= bugetUp;
		}


		BufferedWriter writer = new BufferedWriter(new FileWriter("crypto.out"));
		writer.write(minim.toString());
		writer.close();
	}
}


