  // parcurgerea vectorului de calculatoare sortat
  // la intalnirea unei puteri noi se va incerca
  // upgradarea calculatoarelor precedente
  for (int i = 0; i < N; i++) {
    if (comps[i].first != upNr) {
      if (comps[i].first - comps[i - 1].first > B / sum) break;
      B -= sum * (comps[i].first - comps[i - 1].first);
      upNr = comps[i].first;
    }
    sum += comps[i].second;
  }

  // updatarea puterii maxime in fct de numarul de bani ramasi
  if (B >= sum) {
    upNr += B / sum;
  }

  // afisare rezultat
  WriteData(upNr);
  return 0;
