                cost += 1LL * c[i].upgrade * (power - c[i].power);

                // not enough money to pay the cost
                if (cost > 1ULL * B) {
                    return 0;
                }
            }
        }

        return 1;
    }

    // upperbound binary search

    int find_upper(int left, int right) {
        int max_coins = -1;

        while (left <= right) {
            // mid = power that can be reached by all the
            // computers, having B money available
            int mid = left + (right - left) / 2;

            // check if it's possible to pay cost(mid) money
            if (cost(mid)) {
                left = mid + 1;
                max_coins = mid;
            } else {
                right = mid - 1;
            }
        }

        return max_coins;
    }

    int get_result() {
        // find the maximum power that can be achieved by all the
        // computers having maximum B money
        return find_upper(1, B);
    }

    void print_output(int result) {
        ofstream fout("crypto.out");
        fout << result << endl;
        fout.close();
    }
};

int main() {
    // allocate a Task object on heap
    // call solve method (read, get_result, write)
    // destroy the object and free the memory

    auto* task = new (std::nothrow) Task{};
    if (!task) {
        std::cerr << "new failed: What are you doing? Throw your PC!\n";
        return -1;
    }

    task->solve();
    delete task;
    return 0;
}

