import java.math.BigInteger;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;

public class Crypto {

	private static FileWriter myWriter;
	private static final List<Calculator> calculatorList = new ArrayList<>();
	private static BufferedReader reader;
	public static void main(String[] args) throws IOException {
		try {
			myWriter = new FileWriter("crypto.out");
			reader = new BufferedReader(new FileReader("crypto.in"));
		} catch (FileNotFoundException e) {
			e.printStackTrace();
		} catch (IOException e) {
			e.printStackTrace();
		}
		//citire din fisier
		String[] n_buget = reader.readLine().split(" ");
		long n = Long.parseLong(n_buget[0]);
		BigInteger bani = new BigInteger(n_buget[1]);

		for (int i = 0; i < n; i++) {
			String[] putere_upgrade = reader.readLine().split(" ");
			BigInteger putere = new BigInteger(putere_upgrade[0]);
			BigInteger upgrade = new BigInteger(putere_upgrade[1]);
			calculatorList.add(new Calculator(putere, upgrade));
		}
		calculatorList.sort(new Calculator());

		BigInteger putere = BigInteger.valueOf(0);
		BigInteger suma_upgrade = BigInteger.valueOf(0);
		for (int i = 0; i < n; i++) {
			// daca au aceeasi putere se aduna upgradeul in suma
			BigInteger putere_curenta = calculatorList.get(i).putere;
			BigInteger cost_curent = calculatorList.get(i).upgrade;

			if (putere_curenta.equals(putere)) {
				suma_upgrade = suma_upgrade.add(calculatorList.get(i).upgrade);
			} else {
				BigInteger power_diff = putere.subtract(putere_curenta).abs();
				bani = bani.subtract(power_diff.multiply(suma_upgrade));
				// bani = bani - diff * suma_upgrade
				if (bani.signum() == -1) {
					bani = bani.add(power_diff.multiply(suma_upgrade));
					break;
				}
				putere = putere.add(power_diff); // putere += putere_curenta
				suma_upgrade = suma_upgrade.add(cost_curent); // suma_upgrade += cost_curent
			}
		}
		// cat timp mai am bani
		putere = putere.add(bani.divide(suma_upgrade));
		myWriter.write(putere.toString());
		myWriter.close();
	}
}

