using namespace std;

struct computer {
    long coin;
    long upgrade_cost;
};

void read_input(ifstream &input_file, vector<computer> &computers,
                                long &computers_number, long &budget) {
    input_file >> computers_number >> budget;

    long count = 0, coin, upgrade_cost;

    while (input_file >> coin >> upgrade_cost) {
        computers.push_back(computer());
        computers[count].coin = coin;
        computers[count].upgrade_cost = upgrade_cost;
        count++;
    }
}

bool compare(const computer &a, const computer &b) {
    if (a.coin == b.coin) {  // if coins are equal, sort by cost
        return a.upgrade_cost < b.upgrade_cost;
    }
    return a.coin < b.coin;
}

long upgrade(vector<computer> &computers, long &computers_number, long budget) {
    sort(computers.begin(), computers.end(), compare);
    long min_coin = computers[0].coin;  // get min coin value

    long upgrade_cost = computers[0].upgrade_cost;
    long i = 1;

    while (i < computers_number) {
        if (computers[i - 1].coin != computers[i].coin &&
            (budget - upgrade_cost) >= 0) {
            long dif = computers[i].coin - computers[i - 1].coin;
            if ((budget - upgrade_cost * dif) >= 0) {
                budget -= upgrade_cost * dif;
                computers[i - 1].coin += dif;
                min_coin = computers[i - 1].coin;
            } else if ((budget - upgrade_cost * dif) < 0) {
                long rest = budget / upgrade_cost;
                min_coin += rest;
                return min_coin;
            }
        } else if ((budget - upgrade_cost) < 0) {
            return min_coin;
        } else {
            upgrade_cost += computers[i].upgrade_cost;
            i += 1;
        }
    }

    long rest = budget / upgrade_cost;
    min_coin += rest;

    return min_coin;
}

int main() {
    ifstream input_file;
    ofstream output_file;
    input_file.open("crypto.in");
    output_file.open("crypto.out");

    long computers_number, budget;
    vector<computer> computers;

    read_input(input_file, computers, computers_number, budget);
    input_file.close();

    output_file << upgrade(computers, computers_number, budget);
    output_file.close();

    return 0;
}

