        fin >> n >> budget;
        for (int i = 0, coin_no, upgrade; i < n; i++) {
            fin >> coin_no >> upgrade;
            computers.push_back(Computer(coin_no, upgrade));
        }
        fin.close();
    }

    int get_result() {
        sort(computers.begin(), computers.end(), cmp);

        int res = computers[0].coin_no;
        int i = 1, curr_sum = computers[0].upgrade;

        while (budget > 0) {
            // curr_sum -> suma care trebuie platita pentru a creste puterea
            // celor mai slabe calculatoare din vector, care au putere egala

            // se parcurg calculatoarele care au putere egala
            while (computers[i].coin_no == computers[i-1].coin_no && i < n) {
                curr_sum += computers[i].upgrade;
                i++;
            }

            int possible = budget / curr_sum;
            if (possible == 0)
                return res;
            if (i != n) {
                int last_res = res;
                res += min(possible,
                           (computers[i].coin_no - computers[i - 1].coin_no));
                int bought = res - last_res;
                budget -= curr_sum * bought;
                computers[i - 1].coin_no += bought;
            } else {
                return res + possible;
            }
        }

        return res;
    }

    void print_output(int result) {
        ofstream fout("crypto.out");
        fout << setprecision(4) << fixed << result;
        fout.close();
    }
};

int main() {
    auto* task = new (std::nothrow) Task();
    if (!task) {
        std::cerr << "new failed: WTF are you doing? Throw your PC!\n";
        return -1;
    }
    task->solve();
    delete task;
    return 0;
}

