bool cmp(Coordinates c1, Coordinates c2) { return c1.x < c2.x; }

class Task {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    int N, B;
    // in acest vector se retin perechile monede - cost upgrade
    Coordinates v[1000000];

    void read_input() {
        ifstream fin("crypto.in");
        fin >> N >> B;
        for (int i = 0; i < N; i++) {
            int x, y;
            fin >> x >> y;
            v[i].x = x;
            v[i].y = y;
        }
        fin.close();
    }

    int get_result() {
        sort(v, v + N, cmp);  // sortam vectorul dupa nr de monede crescator
        int i = 0;
        int s = v[0].y;  // in s retinem costul actual al unui upgrade
        while (i + 1 < N) {  // daca nr de monede al urm calculator este egal
            // cu nr de monede care se produce acum crestem costul unui upgrade
            if (v[i].x == v[i + 1].x) {
                s += v[i + 1].y;
                i++;
                continue;
            } else {  // calculam nr de upgradeuri pe care il facem cu s curent
                int count = min(B / s, v[i + 1].x - v[i].x);
                B -= count * s;  // scadem costul upgradeurilor
                if (B < s) {  // daca bugetul scde sub costul unui
                    // upgrade ne oprim
                    return v[i].x + count;
                } else {  // altfel putem continua upgradeurile
                    s += v[i + 1].y;
                    i++;
                }
            }
        }
        // daca am adus toate calculatoarele la acelasi nr de monede pe care
        // le pot produce folosim restul bugetului pentru a upgrada toate
        // calculatoarele de cate ori putem
        return v[N - 1].x + B/s;
    }
    void print_output(int result) {
        ofstream fout("crypto.out");
        fout << result;
        fout.close();
    }
};

