        #include <bits/stdc++.h>
using namespace std;

struct Comp {
	inline bool operator() (const pair<long, long> p1, const pair<long, long> p2) {
		return p1.first < p2.first;
	}
};

int solve(int n, int b,	vector<pair<int, int>> v) {
	int answer;
	long multiple_cost = 0;
	int diff;
	int i = 0;

	for (; i < n - 1; ++i) {
		diff = v[i + 1].first - v[i].first;

		multiple_cost += v[i].second;

		if (multiple_cost * diff > b) {
			return v[i].first + (b / multiple_cost);
		}

		v[i].first += diff;
		b -= multiple_cost * diff;
	}

	// still has money case
	if (i == n - 1) {
		multiple_cost += v[n - 1].second;
	}

	return v[i].first + (b / multiple_cost);
}

int main() {
