	for (int i = 0, x, y; i < n; ++i) {
		in >> x >> y;
		v.push_back(make_pair(x, y));
	}

	// sort by Pi
	sort(v.begin(), v.end(), Comp());

	// write answer
	out << solve(n, b, v);

