        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Comparator;


//folosesc o clasa de perechi - PairCrypto pentru a putea stoca obiecte de tip PairCrypto
//in ArrayList-ul meu (pentru a putea sorta eficient)
class PairCrypto {
	private int cryptoPerHour, cost;

	public PairCrypto(int cryptoPerHour, int cost) {
		this.cryptoPerHour = cryptoPerHour;
		this.cost = cost;
	}

	public int getCryptoPerHour() {
		return cryptoPerHour;
	}

	public int getCost() {
		return cost;
	}
}

public class Crypto {
	public static void main(String[] args) throws IOException {
		//citim din fisierul de intrare "crypto.in"
		BufferedReader br = new BufferedReader(new FileReader("crypto.in"));
		String firstLine = br.readLine();
		ArrayList<PairCrypto> computerList = new ArrayList<PairCrypto>();
		int nr_pc = Integer.parseInt(firstLine.split(" ", 2)[0]);

		for (int i = 0; i < nr_pc; i++) {
			String[] line = br.readLine().split(" ", 2);

			computerList.add(new PairCrypto(Integer.parseInt(line[0]),
					Integer.parseInt(line[1])));
		}

		br.close();

		//sortam lista de calculatoare dupa puterea de calcul iar in caz de egalitate,
		//dupa costul upgrade-ului
		computerList.sort(new Comparator<PairCrypto>() {
			@Override
			public int compare(PairCrypto o1, PairCrypto o2) {
				if (o1.getCryptoPerHour() < o2.getCryptoPerHour()) {
					return -1;
				} else if (o1.getCryptoPerHour() == o2.getCryptoPerHour()) {
					return Integer.compare(o1.getCost(), o2.getCost());
				} else {
					return 1;
				}
			}
		});

		int crypto = computerList.get(0).getCryptoPerHour();
		int money = Integer.parseInt(firstLine.split(" ", 2)[1]);

		//cat timp mai avem bani, facem upgrade-uri
		while (money > 0) {
			for (int i = 0; i < nr_pc; i++) {
				//numarul de criptomonede pe ora creste daca mai am bani si am adus
				//primele calculatoare (respectiv primul calculator) la nivelul celorlate
				//(urmatorul nivel imediat superior)
				//o iau de la inceput cu upgradarea calculatoarelor
				if (crypto < computerList.get(i).getCryptoPerHour() && money >= 0) {
					crypto++;
					break;
				}

				//daca ramanem fara bani, nu mai putem face upgrade-uri si iesim din for
				//respectiv si din while (din cauza conditiei while-ului: money > 0)
				if (money <= 0) {
					break;
				}

				//fac upgrade-ul
				money -= computerList.get(i).getCost();

				//numarul de criptomonede pe ora creste daca am upgradat ultimul calculator
				//o iau de la inceput cu upgradarea calculatoarelor
				if (i == nr_pc - 1 && money >= 0) {
					crypto++;
					break;
				}

			}
		}

		//scriem in fisierul de iesire "crypto.out"
		BufferedWriter bw = new BufferedWriter(new FileWriter("crypto.out"));
		bw.write("" + crypto);

		bw.close();
	}
}

