        import java.io.File;
import java.io.IOException;
import java.io.PrintStream;
import java.util.ArrayList;
import java.util.Collections;

class Computer implements Comparable<Computer> {
	int latency;
	int upgradeCost;

	Computer(int latency, int upgradeCost) {
		this.latency = latency;
		this.upgradeCost = upgradeCost;
	}


	//1 - change -1 - not change
	@Override
	public int compareTo(Computer o) {
		if (latency > o.latency) {
			return 1;
		}
		if (latency < o.latency) {
			return -1;
		}
		if (upgradeCost > o.upgradeCost) {
			return 1;
		}
		return 0;
	}

	@Override
	public String toString() {
		return "Computer{"
				+ ", latency=" + latency
				+ ", upgradeCost=" + upgradeCost
				+ '}';
	}
}

public class Crypto {
	public static void main(String[] args) throws IOException {


		MyScanner scanner = new MyScanner("crypto.in");

		//initializing computers
		int numberOfComputers = scanner.nextInt();
		int myMoney = scanner.nextInt();

		ArrayList<Computer> computers = new ArrayList<>();

		for (int i = 0 ; i < numberOfComputers ; i++) {
			computers.add(new Computer(scanner.nextInt(),scanner.nextInt()));
		}

		//sorting
		Collections.sort(computers);
		PrintStream stream = new PrintStream(new File("crypto.out"));

		int numOfEq = 0;
		long totalCost = computers.get(0).upgradeCost;
		int minLatency = computers.get(0).latency;

		int scopeToUpgrade;

		while (true) {

			//Check, how many pcs with same latency
			while (numOfEq + 1 < computers.size()
					&& computers.get(numOfEq + 1).latency == computers.get(numOfEq).latency) {

				totalCost += computers.get(numOfEq + 1).upgradeCost;
				numOfEq++;
			}

			//if we've iterated through all PCs, we don't have limit for upgrade
			if (numOfEq + 1 < computers.size()) {
				scopeToUpgrade = computers.get(numOfEq + 1).latency;
			} else {
				scopeToUpgrade = -1;
			}

			//If we don't havve limit - upgrade with all money we have
			if (scopeToUpgrade == -1) {
				minLatency += myMoney / totalCost;
				break;
			}


			//if we have limit and are able to upgrade - upgrade
			//all visited pcs and update variables
			//Otherwise update for all money we have
			if (myMoney / totalCost > scopeToUpgrade - minLatency) {
				myMoney -= totalCost * (scopeToUpgrade - minLatency);
				minLatency = scopeToUpgrade;
				numOfEq++;
				totalCost += computers.get(numOfEq).upgradeCost;
			} else {
				minLatency += myMoney / totalCost;
				break;
			}
		}

		stream.println(minLatency);
		stream.close();
	}
}

