        import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

public class Ridge {
	public static void main(String[] args) {
		new Ridge.DataInput().solveRidge();
	}

	public static class DataInput {
		public final String inputFile = "ridge.in";
		public final String outputFile = "ridge.out";

		int N;
		long[][] m;

		private void writeOutput(long result) {
			try {
				FileWriter fw = new FileWriter(outputFile);
				fw.write(result + "");
				fw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		public long getResultRidge() {
			try {
				Scanner scan = new Scanner(new File(inputFile));
				N = scan.nextInt();
				m = new long[N][2];

				long[][] dp = new long[3][N];
				long min;
				m[0][0] = scan.nextLong();
				m[0][1] = scan.nextLong();


				for (int i = 0; i < 3; i++) {
					// make sure that mountain's height isn't less than zero
					if (m[0][0] - i < 0) {
						dp[i][0] = Integer.MAX_VALUE;
					}
					dp[i][0] = m[0][1] * i;
				}

				for (int i = 1; i < N; i++) {
					m[i][0] = scan.nextLong();
					m[i][1] = scan.nextLong();
					for (int j = 0; j < 3; j++) {
						if (m[i][0] - j < 0) {
							dp[j][i] = Long.MAX_VALUE;
						} else {
							min = Long.MAX_VALUE;
							for (int k = 0; k < 3; k++) {
								// verify if it isn's the same height
								if ((m[i][0] - j) != (m[i - 1][0] - k)) {
									// find the minimum cost in mountains with different heights
									if (min > dp[k][i - 1]) {
										min = dp[k][i - 1];
									}
								}
							}
							dp[j][i] = m[i][1] * j + min;
						}
					}
				}
				scan.close();
				return Math.min(Math.min(dp[0][N - 1], dp[1][N - 1]), 
					Math.min(dp[1][N - 1], dp[2][N - 1]));
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		public void solveRidge() {
			writeOutput(getResultRidge());
		}
	}
}

