long ridge(long number_peaks, vector<peak>& peaks) {
    long total_cost;

    vector<long> no_excavations(number_peaks, 0);
    vector<long> one_excavations(number_peaks, 0);
    vector<long> two_excavations(number_peaks, 0);

    one_excavations[0] = peaks[0].cost;
    two_excavations[0] = 2 * peaks[0].cost;

