public class Adrese {

	static class Person {
		/**
		 * Clasa retine informatiile unei persoane
		 */

		String name; // numele persoanei
		List<String> mails; // conturile de mail pe care le detine

		Person(String name, List<String> mails) {
			this.name = name;
			this.mails = new ArrayList<>(mails);
		}
	}


	/**
	 * Construieste un graf de mail-uri. Doua mail-uri sunt conectate intre ele daca au
	 * acelasi user.
	 *
	 * @param graph graful dail-uri care se construieste
	 * @param accounts lista de conruti
	 * @param emails set-ul de mail-uri stocate
	 * @param mailToName map-ul de mail-uri cu userii corspunzatori
	 */
	static void createGraph(Map<String, Set<String>> graph, List<List<String>> accounts,
							HashSet<String> emails, Map<String, String> mailToName) {

		// se parcurg listele de conturi
		for (List<String> account : accounts) {
			String name = account.get(0);
			for (int i = 1; i < account.size(); i++) {
				String email = account.get(i);
				//se adauga in map mail-ul cu user-ul sau
				mailToName.put(email, name);
				// se salveaza mail-ul
				emails.add(email);
				// se creeaza nodul cu mail-ul curent
				graph.putIfAbsent(email, new HashSet<>());
				if (i == 1) {
					continue;
				}

				// se formeaza muchie intre mail-ul curent si celelalte mail-uri ce au acelasi user
				graph.get(email).add(account.get(i - 1));
				graph.get(account.get(i - 1)).add(email);

			}
		}
	}

	/**
	 * Realizeaza o parcurgere dfs pentru determinarea componentelor conexe in graful de mail-uri
	 *
	 * @param currNode nodul din car eincepe parcurgerea
	 * @param graph graful de mail-uri
	 * @param visited lista ce retine toate nodurile vizitate
	 * @param tmp lista de noduri vizitate in timpul parcurgerii
	 */
	static void dfs(String currNode, Map<String, Set<String>> graph, Set<String> visited,
					List<String> tmp) {
		if (visited.contains(currNode)) {
			return;
		}
		visited.add(currNode);
		tmp.add(currNode);
		for (String email : graph.get(currNode)) {
