        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.util.ArrayDeque;
import java.util.Queue;

// A Queue Node
class Node {
	// `(x, y)` represents matrix cell coordinates, and
	// `dist` represents their minimum distance from the source
	int x, y, dist;

	Node(int x, int y, int dist) {
		this.x = x;
		this.y = y;
		this.dist = dist;
	}
}

public class Poduri {
	// Below arrays detail all four possible movements from a cell
	private static final int[] row = {-1, 0, 0, 1};
	private static final int[] col = {0, -1, 1, 0};

	// Function to check if it is possible to go to position `(row, col)`
	// from the current position. The function returns false if `(row, col)`
	// is not a valid position or has a value 0 or already visited.
	private static boolean isValid(char[][] mat, boolean[][] visited, int row, int col,
						int N, int M) {
		return ((row >= 0) && (row < N) && (col >= 0) && (col < M)
				&& (mat[row][col] == 'V' || mat[row][col] == 'D'
				|| mat[row][col] == 'O')
				&& !visited[row][col]);
	}

	// Find the shortest possible route in a matrix `mat` from source
	// cell `(i, j)` to destination cell `(x, y)`
	private static int bfsMethod(char[][] mat, int i, int j, int N, int M) {
		// construct a matrix to keep track of visited cells
		boolean[][] visited = new boolean[N][M];

		// create an empty queue
		Queue<Node> q = new ArrayDeque<>();

		// mark the source cell as visited and enqueue the source node
		visited[i][j] = true;
		q.add(new Node(i, j, 0));

		// stores length of the longest path from source to destination
		int min_dist = 9999;

		// loop till queue is empty
		while (!q.isEmpty()) {
			// dequeue front node and process it
			Node node = q.poll();

			// `(i, j)` represents a current cell, and `dist` stores its
			// minimum distance from the source
			i = node.x;
			j = node.y;
			int dist = node.dist;

			// if the destination is found, update `min_dist` and stop
			if ((i == N - 1 && (mat[i][j] == 'V' || mat[i][j] == 'D'))
				|| (j == M - 1 && (mat[i][j] == 'O' || mat[i][j] == 'D'))
				|| (i == 0 && (mat[i][j] == 'V' || mat[i][j] == 'D'))
				|| (j == 0 && (mat[i][j] == 'O' || mat[i][j] == 'D'))) {
				min_dist = dist + 1;
				break;
			}

			// check for all four possible movements from the current cell
			// and enqueue each valid movement
			for (int k = 0; k < 4; k++) {
				// check if it is possible to go to position
				// `(i + row[k], `j` + col[k])` from current position
				if (k == 0 || k == 3) {
					if (isValid(mat, visited, i + row[k], j + col[k], N, M)
						&& (mat[node.x][node.y] == 'V' ||  mat[node.x][node.y] == 'D')) {
						// mark next cell as visited and enqueue it
						visited[i + row[k]][j + col[k]] = true;
						q.add(new Node(i + row[k], j + col[k], dist + 1));
					}
				}
				if (k == 1 || k == 2) {
					if (isValid(mat, visited, i + row[k], j + col[k], N, M)
						&& (mat[node.x][node.y] == 'O' ||  mat[node.x][node.y] == 'D')) {
						// mark next cell as visited and enqueue it
						visited[i + row[k]][j + col[k]] = true;
						q.add(new Node(i + row[k], j + col[k], dist + 1));
					}
				}
			}
		}
		if (min_dist != 9999) {
			return min_dist;
		}
		return -1;
	}

	public static void main(String[] args) throws Exception {
		File myObj = new File("poduri.in");

		BufferedReader brTest = new BufferedReader(new FileReader(myObj));
		String text = brTest.readLine();
		String[] strArray = text.split(" ");

		int Ni = Integer.parseInt(strArray[0]);
		int Mi = Integer.parseInt(strArray[1]);

		text = brTest.readLine();
		String[] strArray1 = text.split(" ");
		final int Xi = Integer.parseInt(strArray1[0]);
		final int Yi = Integer.parseInt(strArray1[1]);

		char[][] mat = new char[Ni][Mi];
		for (int i = 0; i < Ni; i++) {
			String line = brTest.readLine();
			for (int j = 0; j < Mi; j++) {
				mat[i][j] = line.charAt(j);
			}
		}

		int result = bfsMethod(mat, Xi - 1, Yi - 1, Ni, Mi);

		FileWriter myWriter = new FileWriter("poduri.out");
		myWriter.write(Integer.toString(result));
		myWriter.close();
	}
}

