					bridges[i][j] = line[0].charAt(j - 1);
					Coord new_coord = new Coord(i, j);

					//Daca e chiar pozitia initiala, o adaug in coada de coordonate
					if (i == initial_line && j == initial_col) {
						queue.add(new_coord);
					}
				}
			}
		} catch (IOException ex) {
			ex.printStackTrace();
		}

		//Retine ce coordonate au fost deja vizitate
		boolean[][] was_visited = new boolean[N + 1][M + 1];
		int solution = 0;

		while (queue.size() > 0) {
			int q_size = queue.size();

			while (q_size > 0) {
				Coord coord = queue.remove();

				int line = coord.getLine_coord();
				int col = coord.getCol_coord();
				q_size --;

				//Daca s-a iesit de pe harta, inseamna ca s-a gasit un rezultat
				if (line == N + 1 || line == 0 || col == M + 1 || col == 0) {
					try {
						FileWriter w = new FileWriter("poduri.out");
						w.write(String.valueOf(solution));
						w.close();
					} catch (IOException e) {
						e.printStackTrace();
					}

					return;
				}

				//Daca pozitia curenta a fost vizitata o ignor
				if (was_visited[line][col]) {
					continue;
				}

				//Setez pozitia curenta ca vizitata
				was_visited[line][col] = true;
				char val = bridges[line][col];

				//Adaug coordonatele vecine
				if (val == 'V' || val == 'D') {
					Coord coord_north = new Coord(line + 1, col);
					Coord coord_south = new Coord(line - 1, col);


					queue.add(coord_north);
					queue.add(coord_south);
				}

				if (val == 'O' || val == 'D') {
					Coord coord_east = new Coord(line, col + 1);
					Coord coord_west = new Coord(line, col - 1);

					queue.add(coord_east);
					queue.add(coord_west);
				}
			}

			solution++;
		}

		//Nu s-a gasit solutie
		try {
			FileWriter w = new FileWriter("poduri.out");
			w.write(String.valueOf(-1));
			w.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

