        #include <bits/stdc++.h>
using namespace std;

class Prinel {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    // n = numarul de elemente din vectori
    // k = numarul maxim de operatii ce pot fi efectuate
    // t = vectorul ce contine valorile target
    // p = vectorul ce contine punctele primite daca ajunge la valoarea target
    // max_val = valoarea target maxima din vectorul t
    int n, k;
    vector<int> t;
    vector<int> p;
    int max_val = -1;

    void read_input() {
        ifstream fin("prinel.in");
        fin >> n >> k;
        // citesc target-urile si le pun in vectorul t
        for (int i = 0, e; i < n; i++) {
            fin >> e;
            t.push_back(e);
            if (e > max_val)
                max_val = e;  // actualizez maximul
        }
        // citesc punctele si le pun in vectorul p
        for (int i = 0, e; i < n; i++) {
            fin >> e;
            p.push_back(e);
        }
        fin.close();
    }

    int get_result() {
        // vectorul dp contine numarul de operatii necesare atingerii targetului
        // targetul este indexul
        vector<int> dp(max_val+1, 1000);
        dp[1] = 0;
        for (int l = 1; l <= max_val; l++) {
            int j;
            // calculez divizorii
            for (j = 1; j <= sqrt(l); j++) {
                if (l % j == 0 && l+j <= max_val) {
                    if (l / j == j) {
                        // adaug numarul minim de operatii
                        dp[l+j] = min(dp[l] + 1, dp[l+j]);
                    } else {
                        dp[l+j] = min(dp[l] + 1, dp[l+j]);
                        int d = l / j;
                        // verific daca nu depaseste dimensiunea alocata
                        // matricii
                        if (l+d <= max_val)
                            dp[l+d] = min(dp[l] + 1, dp[l+d]);
                    }
                }
            }
        }
        int sum_op = 0;  // suma operatiilor
        int sum_p = 0;  // suma punctelor
        vector<int> ops(n, -1);  // vectorul de operatii
        for (int i = 0; i < n; i++) {
            // pun in vectorul de operatii numarul de operatii necesar
            // fiecarui target
            ops[i] = dp[t[i]];
            sum_op += ops[i];  // calculez suma operatiilor
            sum_p += p[i];  // calculez suma punctelor
        }

       // daca suma tuturor operatiilor este mai mica sau egala cu maximul
       if (sum_op <= k) {
            return sum_p;  // returnez suma punctelor
       } else {
            // return KnapSack(p, ops, n, k); // folosesc problema Rucsac 0-1
            return rucsac(n, k, ops, p);  // folosesc problema Rucsac 0-1
       }
    }


// n   = numărul de obiecte din colecție
// W   = capacitatea maximă a rucsacului
// (w[i], p[i]) = caracteristicile obiectului i ($i = 1 : n)

int rucsac(int n, int W, vector<int> &w, vector<int> &p) {
    // dp este o matrice de dimensiune (n + 1) x (W + 1)
    // pentru că folosim dp[0][*] pentru mulțimea vidă
    // dp[*][0] pentru situația în care ghiozdanul are capacitate 0
    vector< vector<int> > dp(n + 2, vector<int>(W + 1, 0));
    // cazul de bază
    for (int cap = 0; cap <= W; ++cap) {
        dp[0][cap] = 0;
    }
    // cazul general
    for (int i = 1; i <= n+1; ++i) {
        for (int cap = 0; cap <= W; ++cap) {
            // nu folosesc obiectul i => e soluția de la pasul i - 1
            dp[i][cap] = dp[i-1][cap];
    // folosesc obiectul i, deci trebuie să rezerv w[i] unități în rucsac
    // înseamnă ca înainte trebuie să ocup maxim cap - w[i] unități
            if (cap - w[i-1] >= 0) {
                int sol_aux = dp[i-1][cap - w[i-1]] + p[i-1];
                dp[i][cap] = max(dp[i][cap], sol_aux);
            }
        }
    }
    return dp[n+1][W];
}

    void print_output(int result) {
        ofstream fout("prinel.out");
        fout << result;
        fout.close();
    }
};

int main() {
    auto* prinel = new (nothrow) Prinel();
    prinel->solve();
    delete prinel;
    return 0;
}

