        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.Scanner;

/*
 * am creat o clasa Auxiliar pe care o voi folosi
 * atat pentru un ArrayList care imi va pastra operatiile
 * si punctele corespunzatoare elementului, dar si pentru 
 * un ArrayList pe care il voi folosi la aflarea valorii 
 * maxime posibile
 */
class Auxiliar {
	int val1;
	int val2;

	public Auxiliar(int val1, int val2) {
		this.val1 = val1;
		this.val2 = val2;
	}
}

public class Prinel {
	public static void main(String[] args) throws IOException {
		try (Scanner read = new Scanner(new BufferedReader(
				new FileReader(new File("prinel.in"))))) {
			FileWriter outputFile = new FileWriter("prinel.out");
			int n = read.nextInt(), k = read.nextInt();
			int numberOps = k;
			Integer[] target = new Integer[n];
			/*
			 * opsAndPoints imi pastreaza atat numarul de operatii
			 * cat si punctele elementului
			 */
			ArrayList<Auxiliar> opsAndPoints = new ArrayList<>();
			/*
			 * citesc elementele din target si il pastrez pe cel mai
			 * mare in maxTarget
			 */
			int maxTarget = 0;
			for (int i = 0; i < n; ++i) {
				target[i] = read.nextInt();
				if (target[i] > maxTarget) {
					maxTarget = target[i];
				}
			}
			/*
			 * ops este un vector ce imi va pastra numarul minim de
			 * operatii prin care pot ajunge de la 1 la un element specific,
			 * luand la rand toate elementele de la 1 la maxTarget
			 */
			Integer[] ops = new Integer[maxTarget + 1];
			int minDivisors = 0;
			ops[0] = 0;
			ops[1] = 0;
			/*
			 * numarul minim de operatii pentru fiecare element de la
			 * 1 la maxTarget
			 */
			for (int i = 2; i <= maxTarget; ++i) {
				minDivisors = ops[i - 1] + 1;
				for (int l = 1; l * l <= i; ++l) {
					if ((i % l == 0) && (i - i / l != 0)) {
						if (minDivisors > ops[i - i / l] + 1 && i - i / l != 0) {
							minDivisors = ops[i - i / l] + 1;
						}
						if (minDivisors > ops[i - l] + 1 && i - i / l != 0) {
							minDivisors = ops[i - l] + 1;
						}
					}
				}
				ops[i] = minDivisors;
			}
			/*
			 * citesc in continuare punctele pentru fiecare element
			 * din target pe care, apoi, le adaug in opsAndPoints
			 * alaturi de numarul de operatii corespunzator.
			 * totalPoints imi pastreaza suma tuturor punctelor, iar
			 * din numberOps scad operatiile
			 */
			int totalPoints = 0;
			for (int i = 0; i < n; ++i) {
				int points = read.nextInt();
				opsAndPoints.add(new Auxiliar(ops[target[i]], points));
				numberOps -= ops[target[i]];
				totalPoints += points;
			}
			/*
			 * sortez opsAndPoints in functie de numarul de operatii
			 * crescator
			 */
			Collections.sort(opsAndPoints, new Comparator<Auxiliar>() {

				@Override
				public int compare(Auxiliar o1, Auxiliar o2) {
					return o1.val1 - o2.val1;
				}
			});
			/*
			 * daca numberOps este mai mare sau egal cu 0
			 * inseamna ca pot folosi toate operatiile pentru a
			 * aunge la target, deci numarul maxim de puncte
			 * o sa fie totalPoints
			 */
			if (numberOps >= 0) {
				outputFile.write(String.valueOf(totalPoints));
				outputFile.close();
			} else {
				/*
				 * altfel, iau un array dp, initial initializat cu 0,
				 * care pastreaza valoarea curenta in val2, iar valoarea
				 * anterioara in val1
				 */
				ArrayList<Auxiliar> dp = new ArrayList<Auxiliar>();
				for (int i = 0; i <= k; ++i) {
					dp.add(new Auxiliar(0, 0));
				}
				/*
				 * numarul maxim de puncte obtinute pentru operatii de
				 * la 0 la k
				 */
				for (int i = 0; i < n && opsAndPoints.get(i).val1 <= k; ++i) {
					for (int j = 0; j <= k; ++j) {
						if (j + opsAndPoints.get(i).val1 <= k) {
							if (dp.get(j).val1 + opsAndPoints.get(i).val2 > dp.get(j
									+ opsAndPoints.get(i).val1).val2) {
								dp.get(j + opsAndPoints.get(i).val1).val2 = dp.get(j).val1
										+ opsAndPoints.get(i).val2;
							}
							dp.get(j).val1 = dp.get(j).val2;
						}
					}
				}
				/*
				 * in final, valoarea maxima de puncte de gaseste pe ultima pozitia
				 * din dp, de pe valoarea curenta
				 */
				outputFile.write(String.valueOf(dp.get(k).val2));
				outputFile.close();
			}
		}
	}
}
