        #include <fstream>
using namespace std;

ifstream f("regele.in");
ofstream g("regele.out");

typedef struct {
    int cost, coord;
}Oras;

int dp[2001][1001] = {0}, partial_max[1001][2001] = {0};

int main() {
    int n, q, m, negustori_max[1001] = {0};
    Oras orase[2001];
    f >> n;
    for (int i = 1; i <= n; ++i) {
        f >> orase[i].coord;
    }

    // dp[i][k] = nr minim de negustori necesari
    // pentru a activa orice k orase de la 1 la i,
    // cu ultimul oras fiind i

    // partial_max[k][i] retine maximul din dp
    // pentru a activa orice k orase de la 1 la i

    // negustori_max[i] = nr de negustori necesar pt activa
    // orice i orase din toate cele n

    // voi presupune ca vom avea cel putin 2 orase
    // altfel, problema nu ar avea sens
    orase[1].cost = orase[2].coord - orase[1].coord;
    dp[1][1] = orase[1].cost;
    partial_max[1][1] = dp[1][1];
    for (int i = 2; i < n; ++i) {
        orase[i].cost = orase[i + 1].coord - orase[i - 1].coord;
        dp[i][1] = orase[i].cost;
        partial_max[1][i] = max(partial_max[1][i - 1], dp[i][1]);
    }
    orase[n].cost = orase[n].coord - orase[n - 1].coord;
    dp[n][1] = orase[n].cost;
    partial_max[1][n] = max(partial_max[1][n - 1], dp[n][1]);

    negustori_max[1] = partial_max[1][n];

    // am completat deja pt k = 1
    for (int k = 2; k <= n / 2; ++k) {
        for (int i = k * 2 - 1; i <= n ; ++i) {
            dp[i][k] = orase[i].cost + partial_max[k - 1][i - 2];
            partial_max[k][i] = max(partial_max[k][i - 1], dp[i][k]);
        }
        negustori_max[k] = partial_max[k][n];
    }
    f >> q;
    for (int i = 1; i <= q; ++i) {
        f >> m;
        // nr de negustori necesar activarii oricaror
        // n / 2 -> n orase este acelasi, si anume
        // costul activarii tuturor drumurilor
        if (m >= orase[n].coord - orase[1].coord) {
            g << n << '\n';
        } else {
            // facem o cautare binara in negustori_max
            int dreapta = n / 2, stanga = 0, middle;
            while (stanga + 1 < dreapta) {
                middle = (stanga + dreapta) / 2;
                if (negustori_max[middle] == m) {
                    break;
                } else if (negustori_max[middle] > m) {
                    dreapta = middle;
                } else {
                    stanga = middle;
                }
            }
            if (negustori_max[middle] == m) {
                g << middle << '\n';
            } else {
                g << stanga << '\n';
                }
        }
    }
    return 0;
}

