        #include <bits/stdc++.h>

using namespace std;

class Task {
 public:
        void solve() {
            read_input();
            print_output(get_result());
        }

 private:
        int n, l;
        vector < string > words;

        void read_input() {
            ifstream fin("statistics.in");
            fin >> n;
            words.resize(n + 1);
            for (int i = 1; i <= n; i++) {
                fin >> words[i];
            }
            fin.close();
        }

        // returneaza numarul maxim de cuvinte din lista astfel încât, în urma
        // concatennarii caracterul letter sa fie dominant
        int greedy(char letter) {
            vector < int > v(n + 1);
            // v[i] = numarul aparitiilor caracterului letter
            //        - numarul aparitiilor celorlalte caractere
            for (int i = 1; i <= n; i++) {
                v[i] = 2 * count(words[i].begin(), words[i].end(), letter)
                           - words[i].size();
            }

            // sortez vectorul descrescator
            sort(v.begin() + 1, v.end(),
                [](int p1, int p2) {
                    return p1 > p2;
                });

            // includ cuvantul i doar daca diff + v[i] > 0
            int diff = 0, cnt = 0;
            for (int i = 1; i <= n; i++) {
                if (diff + v[i] > 0) {
                    diff += v[i];
                    cnt++;
                    continue;
                }
                break;
            }
            return cnt == 0 ? -1 : cnt;
        }

        int get_result() {
            int maximum = 0, ans;
            for (char i = 'a'; i <= 'z'; i++) {
                ans = greedy(i);
                if (ans > maximum)
                    maximum = ans;
            }
            return maximum;
        }

        void print_output(int result) {
            ofstream fout("statistics.out");
            fout << result;
            fout.close();
        }
};

int main() {
    auto * task = new(nothrow) Task();
    task -> solve();
    delete task;
    return 0;
}

