        import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Arrays;
import java.util.Comparator;

public class Statistics {
	static final String INPUT = "statistics.in";
	static final String OUTPUT = "statistics.out";
	static final char[] alphabet = {'a', 'b', 'c', 'd', 'e', 'f', 'g', 'h', 'i', 'j', 'k', 'l',
		'm', 'n', 'o', 'p', 'q', 'r', 's', 't', 'q', 'u', 'v', 'w', 'x', 'y', 'z'};

	// Metoda ce numara de cate ori apare un caracter intr-un string:
	public static int countOccurences(char c, String word) {
		int res = 0;
		for (int i = 0; i < word.length(); i++) {
			if (c == word.charAt(i)) {
				res++;
			}
		}
		return res;
	}
	// Metoda care calculeaza cate litere are cuvantul, inafara de un caracter dat:
	public static int countOther(char c, String word) {
		int res = 0;
		for (int i = 0; i < word.length(); i++) {
			if (c != word.charAt(i)) {
				res++;
			}
		}
		return res;
	}

	// Metoda ce calculeaza maximul de cuvinte care concatenate, formeaza un cuvant
	// cu litera dominanta:
	public static int findMax(String[] words) {
		// max va retine maximul de cuvinte:
		int max = 0;
		// Pentru fiecare litera din alfabet:
		for (char c : alphabet) {
			// Sortez vectorul de cuvinte dupa numarul de aparitii al literei
			// curente, raportant de numarul celorlalte litere:
			Arrays.sort(words, new Comparator<String>() {
				public int compare(String word1, String word2) {
					if (countOccurences(c, word1) - countOther(c, word1)
							> countOccurences(c, word2) - countOther(c, word2)) {
						return -1;
					} else if (countOccurences(c, word1) - countOther(c, word1)
							== countOccurences(c, word2) - countOther(c, word2)) {
						return 0;
					}
					return 1;
				}
			});
			// wordsCounter numara cate cuvinte am concatenat din vectorul sortat:
			int wordsCounter = 0;
			// solution retine cuvantul format prin concatenarea cuvintelor din vector:
			String solution = "";
			// Pentru fiecare cuvant din vector:
			for (String word : words) {
				// Daca nr. aparitiilor literei curente este mai mare decat
				// cel al celorlalte litere:
				if (countOccurences(c, word) - countOther(c, word) >= 0) {
					// incrementez wordsCounter si concatenez cuv. curent la solution:
					wordsCounter++;
					solution = solution + word;
					// Daca in cuvantul curent nu exista litera curenta,
					// dar dupa concatenare se respecta regula existentei
					// unei litere dominante:
				} else if ((word.length() + solution.length()) / 2
						< countOccurences(c, solution + word)) {
					// incrementez wordsCounter si concatenez cuv. curent la solution:
					wordsCounter++;
					solution = solution + word;
				} else {
					break;
				}
			}
			// Daca nr. de cuvinte concatenate pt sortarea curenta este maximul de
			// pana acum:
			if (max < wordsCounter) {
				max = wordsCounter;
			}
		}
		// Daca nu s-a gasit nicio solutie cu litera dominanta:
		if (max == 0) {
			return -1;
		}
		return max;
	}
	public static void main(String[] args) throws IOException {
		// Deschid fisierul de input:
		File input = new File(INPUT);
		BufferedReader br = new BufferedReader(new FileReader(input));
		String antet = br.readLine();
		int dim = Integer.parseInt(antet);
		String[] words = new String[dim];
		// Scriu cuvintele extrase din fisierul de input intr-un vector:
		for (int i = 0; i < dim; i++) {
			words[i] = br.readLine();
		}
		FileWriter output = new FileWriter(OUTPUT);
		// Scriu rezultatul intr-un fisier de output:
		output.write(findMax(words) + "\n");
		output.close();
	}
}

