import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Arrays;
import java.util.Collections;
import java.util.Scanner;

public class Statistics {

	static int getCharDifference(char c, String s) {
		int count = (int) s.chars().filter(ch -> ch == c).count();
		return count - (s.length() - count);
	}

	static int getMaxDiff(String[] words, char c) {
		int max = 0;
		int chardif = 0;
		Integer[] v = new Integer[words.length];

		for (int j = 0 ; j < words.length ; j++) {
			v[j] = getCharDifference(c,words[j]);
		}
		Arrays.sort(v, Collections.reverseOrder());


		for (Integer i : v) {
			chardif += i;
			if (chardif <= 0) {
				break;
			} else {
				max++;
			}
		}
		return max;
	}


	public static void main(String[] args) throws IOException {
		File myObj = new File("statistics.in");
		Scanner myReader = new Scanner(myObj);
		int n = myReader.nextInt();
		String[] words = new String[n];
		myReader.nextLine();
		for (int i = 0; i < n; i++) {
			words[i] = myReader.nextLine();
		}
		int i = 0;
		int max = getMaxDiff(words, 'a');
		for (char c = 'b'; c <= 'z'; ++c, i++) {
			int local_max = getMaxDiff(words, c);
			if (local_max > max) {
				max = local_max;
			}
		}
		FileWriter myWriter = new FileWriter("statistics.out");
		myWriter.write(Integer.toString(max) + "\n");
		myWriter.close();
	}
}
