void fill_horizontal(int n, int m, vector<vector<char>> &matrix,
                     vector<vector<int>> &horizontal) {
    for (int i = 0; i < n; i++) {
        if (i > 0 && matrix[i - 1][m - 1] == '.') {
            node++;
        }
        for (int j = 0; j < m; j++) {
            if (matrix[i][j] == '.') {
                horizontal[i][j] = node;
            } else {
                if (j > 0 && matrix[i][j - 1] == '.') {
                    node++;
                }
                continue;
            }
        }
    }
    node++;
}

void fill_vertical(int n, int m, vector<vector<char>> &matrix,
                   vector<vector<int>> &vertical) {
    for (int j = 0; j < m; j++) {
        if (j > 0 && matrix[n - 1][j - 1] == '.') {
            node++;
        }
        for (int i = 0; i < n; i++) {
            if (matrix[i][j] == '.') {
                vertical[i][j] = node;
            } else {
                if (i > 0 && matrix[i - 1][j] == '.') {
                    node++;
                }
                continue;
            }
        }
    }
}

void bfs(int src, int dest1, int dest2, int n, int m, vector<int> adj[]) {
    queue<pair<int, int>> q;

    vector<int> d(node + 1, INF);
    d[src] = 0;
    q.push({d[src], src});
    while (!q.empty()) {
        auto p = q.front();
        q.pop();
        int node = p.second;
        if (node == dest1 || node == dest2) {
            sol = min(sol, p.first);
        }
        for (auto neigh : adj[node]) {
            if (d[neigh] > d[node] + 1) {
                d[neigh] = d[node] + 1;
                q.push({d[neigh], neigh});
            }
        }
    }
}

