			this.yi = Integer.parseInt(splitPositions[1]);
			this.xf = Integer.parseInt(splitPositions[2]);
			this.yf = Integer.parseInt(splitPositions[3]);

			for (int i = 0; i < this.N; i++) {
				String line = reader.readLine();

				for (int j = 0; j < this.M; j++) {
					if (line.charAt(j) == 'W') {
						this.graphMatrix[i][j] = Integer.MAX_VALUE;
					} else {
						this.graphMatrix[i][j] = -1;
					}
				}
			}

			BufferedWriter printer = new BufferedWriter(new FileWriter(OUTPUT_FILE));
			printer.write(String.valueOf(solve()));

