					queue.add(new Triplet(topPair.getX(), i, topPair.getCost() + 1));
					if (this.graphMatrix[this.xf][this.yf] != -1) {
						finalResult = Math.min(finalResult, this.graphMatrix[this.xf][this.yf]);
						return finalResult;
