			for (int i = topPair.getY() - 1; i >= 0; i--) {
				if (this.graphMatrix[topPair.getX()][i] == Integer.MAX_VALUE) {
					break;
				} else if (this.graphMatrix[topPair.getX()][i] == -1) {
