const int nmax = 1000;
int viz[nmax][nmax];

int find_minimum_moves(vector <string> grid, int startX, int startY,
int destX, int destY) {
    int N = grid.size();
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (grid[i][j] =='W') {
                viz[i][j] = -1;
            } else {
                viz[i][j] = N * N;
            }
        }
    }
    queue<pair<int, int>> q;
    q.push(make_pair(startX, startY));
    viz[startX][startY] = 0;
    while (!q.empty()) {
        pair<int, int> curr = q.front();
        q.pop();
        for (int i = 1; curr.first-i >= 0 &&
        viz[curr.first-i][curr.second] > 0; i++) {
            if (viz[curr.first-i][curr.second] <
            viz[curr.first][curr.second] + 1) {
                break;
            }
            viz[curr.first-i][curr.second] = viz[curr.first][curr.second] + 1;
            q.push(make_pair(curr.first-i, curr.second));
        }
        for (int i = 1; curr.first+i < N &&
        viz[curr.first+i][curr.second] > 0; i++) {
            if (viz[curr.first+i][curr.second] <
            viz[curr.first][curr.second] + 1) {
                break;
            }
            viz[curr.first+i][curr.second] = viz[curr.first][curr.second] + 1;
            q.push(make_pair(curr.first + i, curr.second));
        }
        for (int i = 1; curr.second-i >= 0 &&
        viz[curr.first][curr.second-i] > 0; i++) {
            if (viz[curr.first][curr.second-i] <
            viz[curr.first][curr.second] + 1) {
                break;
            }
            viz[curr.first][curr.second-i] = viz[curr.first][curr.second] + 1;
            q.push(make_pair(curr.first, curr.second-i));
        }
        for (int i = 1; curr.second + i < N &&
        viz[curr.first][curr.second + i]>0; i++) {
            if (viz[curr.first][curr.second+i] <
            viz[curr.first][curr.second] + 1) {
                break;
            }
            viz[curr.first][curr.second+i] = viz[curr.first][curr.second] + 1;
            q.push(make_pair(curr.first, curr.second + i));
        }
    }
    return viz[destX][destY] - 1;
}

int main() {
    ifstream fin("beamdrone.in");
    ofstream fout("beamdrone.out");
    int n, m;
    fin >> n >> m;
    int startX, startY, destX, destY;
    fin >> startX >> startY >> destX >> destY;

    vector<string> grid;

    for (int i = 0; i < n; i++) {
            string c;
            fin >> c;
            grid.push_back(c);
    }
    fout << find_minimum_moves(grid, startX, startY, destX, destY);
}

