            if (node.second == 1) {
                for (int i = x - 1; i >= 0; i--) {
                    if (matrice[i][y] == 'W')
                        break;
                    if (d[i][y] == INF) {
                        d[i][y] = d[x][y] + 1;
                        if (i == xf && y == yf)
                            goto E;
                        else
                            q.push({ {i, y}, 0 });
                    }
