                for (int i = x + 1; i < n; i++) {
                    if (matrice[i][y] == 'W')
                        break;
                    if (d[i][y] == INF) {
                        d[i][y] = d[x][y] + 1;
                        if (i == xf && y == yf)
                            goto E;
                        else
                            q.push({ {i, y}, 0 });
                    }
                }


            } else {
                for (int i = y - 1; i >= 0; i--) {
                    if (matrice[x][i] == 'W')
                        break;
                    if (d[x][i] == INF) {
                        d[x][i] = d[x][y] + 1;
                        if (x == xf && i == yf)
                            goto E;
                        else
                            q.push({ {x, i}, 1 });
                    }
                }

                for (int i = y + 1; i < m; i++) {
                    if (matrice[x][i] == 'W')
                        break;
                    if (d[x][i] == INF) {
                        d[x][i] = d[x][y] + 1;
                        if (x == xf && i == yf)
                            goto E;
                        else
                            q.push({ {x, i}, 1 });
                    }
                }
            }
        }


    E:

        // scriem rezultatul in fisierul de iesire
        ofstream fout("beamdrone.out");
        fout << d[xf][yf];
        fout.close();
    }
};


