        import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedList;
import java.util.Queue;

public class Beamdrone {

	// parcurgere bfs pentru a determina distanța de la start la target cell
	static int bfs(ArrayList<HashSet<Integer>> graf, int start, int target1, int target2) {
		// coadă noduri în așteptare
		Queue<Integer> q = new LinkedList<>();
		q.add(start);
		// mulțime noduri vizitate
		int[] viz = new int[graf.size() + 1];
		int dist = 0;
		viz[start] = 1;

		// cât timp mai sunt noduri de vizitat
		while (!q.isEmpty()) {
			int size = q.size();

			// se procesează nodurile aflate la distanța dist de nodul de start
			for (int i = 0; i < size; i++) {
				int nod = q.poll();
				// s-a găsit nodul target orizontal
				if (nod == target1) {
					return dist;
				}
				// s-a găsit nodul target vertical
				if (nod == target2) {
					return dist;
				}
				// vizitare vecini
				for (int vecin : graf.get(nod)) {
					// se adaugă în coadă vecinii nevizitați
					if (viz[vecin] == 0) {
						viz[vecin] = 1;
						q.add(vecin);
					}
				}
			}
			// se incrementează distanța de la sursă
			dist++;
		}
		// nu există drum până la target
		return -1;
	}

	public static void main(String[] args) throws IOException {
		BufferedReader in = new BufferedReader(
				new FileReader("beamdrone.in"));

		final PrintWriter out = new PrintWriter("beamdrone.out", "UTF-8");

		// citire input
		String firstLine = in.readLine();
		String[] first = firstLine.split(" ");
		int rows = Integer.parseInt(first[0]);
		int cols = Integer.parseInt(first[1]);

		String secondLine = in.readLine();
		String[] second = secondLine.split(" ");
		int drow = Integer.parseInt(second[0]);
		int dcol = Integer.parseInt(second[1]);
		int frow = Integer.parseInt(second[2]);
		int fcol = Integer.parseInt(second[3]);

		// obținere indici noduri sursă și target
		final int source = drow * rows + dcol + 1;
		final int dest = frow * rows + fcol + 1;

		char[][] mat = new char[rows][cols];

		// mapare celulă din grid la nodul orizontal, respectiv
		// vertical de care aparține
		int[][] cellBelongs = new int[rows * cols + 1][2];

		// indicele nodului curent
		int curr = 0;

		// graful format din nodurile orizntale și verticale reunite
		ArrayList<HashSet<Integer>> graf = new ArrayList<>();
		graf.add(new HashSet<>());

		// generare noduri orizontale
		for (int row = 0; row < rows; row++) {
			char[] r = in.readLine().toCharArray();
			// nod orizontal nou
			graf.add(new HashSet<>());
			curr++;

			int col = 0;
			// se sare peste locurile inaccesibile de la început de rând
			while (col < cols && r[col] == 'W') {
				mat[row][col] = 'W';
				col++;
			}

			while (col < cols) {
				if (col < cols) {
					mat[row][col] = r[col];
					// dacă este un loc accesibil
					if (mat[row][col] == '.') {
						int pos = row * rows + col + 1;

						// atribuire celulă din grid cu nodul orizontal
						cellBelongs[pos][0] = curr;
						col++;
					} else { // perete
						curr++;
						graf.add(new HashSet<>());

						while (col < cols && mat[row][col] == 'W') {
							col++;
						}
					}
				}
			}
		}
		// generare noduri verticale
		for (int col = 0; col < cols; col++) {
			// nod vertical nou
			curr++;
			graf.add(new HashSet<>());

			int row = 0;
			// se sare peste locurile inaccesibile de la început de coloană
			while (row < rows && mat[row][col] == 'W') {
				row++;
			}

			while (row < rows) {
				if (row < rows) {
					// dacă este un loc accesibil
					if (mat[row][col] == '.') {
						int pos = row * rows + col + 1;

						// atribuire celulă din grid cu nodul vertical
						cellBelongs[pos][1] = curr;
						int nod1 = cellBelongs[pos][0];
						int nod2 = cellBelongs[pos][1];
						// creare graf prin adăugarea de muchii între nodurile orizontale
						// și cele verticale pe baza intersecției acestora prin celulele
						// din grid din componența acestora
						graf.get(nod1).add(nod2);
						graf.get(nod2).add(nod1);
						row++;
					} else { // perete
						curr++;
						graf.add(new HashSet<>());

						while (row < rows && mat[row][col] == 'W') {
							row++;
						}
					}
				}
			}
		}

		// definire posibile poziții de start și finish
		int start1 = cellBelongs[source][0];
		int start2 = cellBelongs[source][1];

		// la început drona se poate afla în orice direcție
		for (int vecini : graf.get(start2)) {
			graf.get(start1).add(vecini);
		}

		int dest1 = cellBelongs[dest][0];
		int dest2 = cellBelongs[dest][1];

		// calcularea celei mai mici distanțe de la start la finish
		int d1 = bfs(graf, start1, dest1, dest2);

		// se afișează distanța minimă obținută
		out.println(d1);

		out.close();

		in.close();

	}
}

