        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.LinkedList;
import java.util.Queue;

public class Beamdrone {
	static int N, M;
	static char[][] matrix = new char[1000][1000];
	static int[][] distances = new int[1000][1000];
	static Node source, destination;

	static class Node {
		int x, y, last;
		public Node(int x, int y, int last) {
			this.x = x;
			this.y = y;
			this.last = last;
		}   
	}

	static int[] rowCoord = { -1, 0, 1, 0 };
	static int[] colCoord = { 0, 1, 0, -1 };

	/* Verific sa nu ies din matrice si sa nu merg intr-un perete. */
	static boolean isValid(int row, int col) {
		if (row < 0 || col < 0 || row >= N || col >= M) {
			return false;
		}

		if (matrix[row][col] == 'W') {
			return false;
		}

		return true;
	}

	/* Functia implementeaza algoritmul lui Lee  modificat. x este coordonata
	pentru directia N-S, cand x scade merg spre nord. y este coordonata pentru
	directia W-E, cand y scade merg spre vest. */
	static int bfs() {
		for (int i = 0; i < N; i++) {
			for (int j = 0; j < M; j++) {
				distances[i][j] = Integer.MAX_VALUE;
			}
		}

		Queue<Node> queue = new LinkedList<>();
		distances[source.x][source.y] = 0;
		int newX, newY;

		/* Pornind din sursa, pun distanta 0 in directia N pana la margine
		sau pana la primul perete. */
		newX = source.x - 1;
		newY = source.y;
		while (isValid(newX, newY)) {
			distances[newX][newY] = 0;
			queue.add(new Node(newX, newY, 0));
			newX--;
		}

		/* Pornind din sursa, pun distanta 0 in directia E pana la margine
		sau pana la primul perete. */
		newX = source.x;
		newY = source.y + 1;
		while (isValid(newX, newY)) {
			distances[newX][newY] = 0;
			queue.add(new Node(newX, newY, 1));
			newY++;
		}

		/* Pornind din sursa, pun distanta 0 in directia S pana la margine
		sau pana la primul perete. */
		newX = source.x + 1;
		newY = source.y;
		while (isValid(newX, newY)) {
			distances[newX][newY] = 0;
			queue.add(new Node(newX, newY, 2));
			newX++;
		}

		/* Pornind din sursa, pun distanta 0 in directia W pana la margine
		sau pana la primul perete. */
		newX = source.x;
		newY = source.y - 1;
		while (isValid(newX, newY)) {
			distances[newX][newY] = 0;
			queue.add(new Node(newX, newY, 3));
			newY--;
		}

		while (!queue.isEmpty()) {
			Node node = queue.poll();
			int x = node.x;
			int y = node.y;
			int last = node.last;

			/* Merg in fiecare din cele 4 directii. */
			for (int i = 0; i < 4; i++) {
				newX = x + rowCoord[i];
				newY = y + colCoord[i];
				/* Pana cand dau de margine sau zid. */
				while (isValid(newX, newY)) {
					/* Daca merg in aceeasi directie costul este acelasi. */
					if (last == i) {
						if (distances[newX][newY] == Integer.MAX_VALUE) {
							distances[newX][newY] = distances[x][y];
							queue.add(new Node(newX, newY, i));
						} else if (distances[newX][newY] == distances[x][y]) {
							break;
						}
					/* Daca merg in alta directie costul se incrementeaza. */
					} else {
						if (distances[newX][newY] == Integer.MAX_VALUE) {
							distances[newX][newY] = distances[x][y] + 1;
							queue.add(new Node(newX, newY, i));
						} else if (distances[newX][newY] == distances[x][y]) {
							break;
						}
					}

					if (newX == destination.x && newY == destination.y) {
						return distances[newX][newY];
					}

					/* Merg in directia setata o casuta in plus. */
					newX = newX + rowCoord[i];
					newY = newY + colCoord[i];
				}
			}
		}
		return distances[destination.x][destination.y];
	}

	public static void main(String[] args) throws IOException {
		BufferedReader reader = new BufferedReader(new FileReader("beamdrone.in"));
		String line = reader.readLine();
		String[] splitted = line.split(" ");
		N = Integer.parseInt(splitted[0]);
		M = Integer.parseInt(splitted[1]);
		line = reader.readLine();
		splitted = line.split(" ");
		source = new Node(Integer.parseInt(splitted[0]), Integer.parseInt(splitted[1]), -1);
		destination = new Node(Integer.parseInt(splitted[2]), Integer.parseInt(splitted[3]), -1);
		for (int i = 0; i < N; i++) {
			line = reader.readLine();
			for (int j = 0; j < M; j++) {
				matrix[i][j] = line.charAt(j);
			}
		}
		reader.close();

		String output = Integer.toString(bfs()) + '\n';
		BufferedWriter writer = new BufferedWriter(new FileWriter("beamdrone.out"));
		writer.write(output);
		writer.close();
	}
}

