        #include <bits/stdc++.h>
#include <fstream>

using namespace std;

int dx[] = {0, 1, -1, 0};
int dy[] = {-1, 0, 0, 1};

struct point {
	int x;
	int y;
	int dir;
	int prio;
};

struct point_comparator {
	bool operator() (point const& p1, point const& p2) {
		return p1.prio > p2.prio;
	}
};

struct cell {
	int w;
	int dir[4] = {INT_MAX, INT_MAX, INT_MAX, INT_MAX};
};

int main() {
	ifstream fin("beamdrone.in");
	ofstream fout("beamdrone.out");

	int n, m, i, j, xi, yi, xf, yf;
    char x;
    vector<vector<cell>> matrix(1000, vector<cell>(1000));

    /* Read input */
    fin >> n >> m >> xi >> yi >> xf >> yf;
    for (i = 0; i < n; i++) {
        for (j = 0; j < m; j++) {
            fin >> x;
            if (x == '.') {
                matrix[i][j].w = 0;
            } else if (x == 'W') {
                matrix[i][j].w = 1;
            }
        }
    }

	/* Run Dijkstra-like algoritm */
	priority_queue<point, vector<point>, point_comparator> pq;
	point curr, next;
	int min, dist;

	/* Start with first 4 neighbours of first cell */
	matrix[xi][yi].dir[0] = 0;
	matrix[xi][yi].dir[1] = 0;
	matrix[xi][yi].dir[2] = 0;
	matrix[xi][yi].dir[3] = 0;
	next.prio = 0;
	for (i = 0; i < 4; i++) {
		next.x = xi + dx[i];
		next.y = yi + dy[i];
		if (next.x >= 0 && next.x < n && next.y >= 0 && next.y <m) {
			if (matrix[next.x][next.y].w == 0) {
				matrix[next.x][next.y].dir[i] = 0;
				next.dir = i;
				pq.push(next);
			}
		}
	}

	while (!pq.empty()) {
		curr = pq.top();
		pq.pop();

		for (i = 0; i < 4; i++) {
			/* No turning back! */
			if (i + curr.dir == 3) {
				continue;
			}

			/* Get each next neighbour */
			next.x = curr.x + dx[i];
			next.y = curr.y + dy[i];

			/* Get distance to it */
			if (i == curr.dir) {
				dist = curr.prio;
			} else {
				dist = curr.prio + 1;
			}

			/* Check if better path was found */
			if (next.x >= 0 && next.x < n && next.y >= 0 && next.y < m) {
				if (matrix[next.x][next.y].w == 0) {
					min = INT_MAX;
					for (j = 0; j < 4; j++) {
						if (min > matrix[next.x][next.y].dir[j]) {
							min = matrix[next.x][next.y].dir[j];
						}
					}
					if (dist < min) {
						matrix[next.x][next.y].dir[i] = dist;
						next.prio = dist;
						next.dir = i;
						pq.push(next);
					} else if (dist == min) {
						if (dist < matrix[next.x][next.y].dir[i]) {
							matrix[next.x][next.y].dir[i] = dist;
							next.prio = dist;
							next.dir = i;
							pq.push(next);
						}
					}
				}
			}
		}
	}

	min = matrix[xf][yf].dir[0];
	for (i = 1; i < 4; i++) {
		if (min > matrix[xf][yf].dir[i]) {
			min = matrix[xf][yf].dir[i];
		}
	}
	fout << min;

	fin.close();
	fout.close();
	return 0;
}

