	vector<int> exists;
	vector<long long> position;
};

struct road {
	int neigh;
	long long cost;
};

struct myComp {
    constexpr bool operator()(
        pair<long long, long long> const& a,
        pair<long long, long long> const& b)
        const noexcept {
        return a.second > b.second;
    }
};

/**
 * @brief Functia dijsktra se ocupa cu rularea algoritmului cu acelasi nume
 * pe graful ce constituie harta pentru a determina drumurile minime de la
 * nodul de start catre toate celelalte noduri din graf.
 * 
 * @param source Nodul de unde pornim calcularea drumurilor minime
 * @param n Numarul de noduri din graf
 * @param routes Vectorul ce contine vectorii de vecini ai fiecarui nod din
 * graf
 * @return o pereche de vectori (vectorul de distante, vectorul de parinti)
 */
pair<vector<long long>, vector<long long>> dijsktra(long long source,
		long long n, vector<vector<road>> routes) {
	priority_queue<pair<long long, long long>,
		vector<pair<long long, long long>>, myComp> pq;
	vector<long long> d(n + 1, LONG_LONG_MAX);
	vector<long long> p(n + 1, INIT);
	pair<long long, long long> element;

	d[source] = 0;
	p[source] = INIT;
	element = make_pair(source, d[source]);
	pq.push(element);

	while (!pq.empty()) {
		element = pq.top();
		pq.pop();
		long long node = element.first;
		for (auto& elem : routes[node]) {
			if (d[node] + elem.cost < d[elem.neigh]) {
				d[elem.neigh] = d[node] + elem.cost;
				p[elem.neigh] = node;

				element = make_pair(elem.neigh, d[elem.neigh]);
				pq.push(element);
			}
		}
	}
	return make_pair(d, p);
}

