 * prin care barbarii pot ajunge la capitala. Calculeaza uniform cat de
 * mult pot fi incetinite armatele barbare si intoarce rezultatul.
 * 
 * @param distances vector sortat ce contine distantele tuturor rutelor
 * posibile de la capitala catre satele barbare
 * @param k numarul de fortificatii disponibile
 * @return distanta minima de la capitala la un sat barbar dupa
 * fortificarea drumurilor
 */
long long fortify(vector<long long> distances, long long k) {
	long long limit = 0, diff, mn;
	mn = distances[0];
	while(k > 0) {
		if (limit < (long long)distances.size()) {
			limit++;
		}
		diff = distances[limit] - distances[limit - 1];
		if (diff < 1) {
			if (limit == (long long)distances.size()) {
				diff = k / limit;
				return mn + diff;
			} else {
				continue;
			}
		}
		if (k / limit >= diff) {
			mn += diff;
			k -= diff * limit;
		} else {
			if (limit == 1) {
				return mn + k;
			}
			diff = k / limit;
			k = 0;
			return mn + diff;
		}
	}
	return mn;
}

