    if (c[1][0] > mod)
        c[1][0] %= mod;
    c[1][1] = a[1][0] * b[0][1] + a[1][1] * b[1][1];
    if (c[1][1] > mod)
        c[1][1] %= mod;
    a[0][0] = c[0][0];
    a[0][1] = c[0][1];
    a[1][0] = c[1][0];
    a[1][1] = c[1][1];
}

unsigned long long fibonacci(unsigned long long n) {
    // cazurile de baza
    if (n == 0)
