    unsigned long long result[2][2] = {{1, 1}, {1, 0}};
    unsigned long long fib[2][2] = {{1, 1}, {1, 0}};
    while (n > 0) {
        if (n % 2 == 1)
            multiply(result, fib);
        n = n / 2;
        multiply(fib, fib);
    }
    return result[0][1];
}


