void fib(uint64_t n, vector <ll>& res) {
  /*
    F(2k) = F(k) * [2 * F(k + 1) - F(k)]
    F(2k + 1) = F(k + 1) ^ 2 + F(k) ^ 2
  */

    if (n == 0) {  // caz de baza
        res[0] = 0;
        res[1] = 1;
        return;
