    // daca n e impar
    fib((n / 2), res);

    a = res[0];  // F(k)
    b = res[1];  // F(k + 1)

    c = 2 * b - a;  // 2 * F(k + 1) - F(k)

    if (c < 0) {  // daca e negativ
      c += MOD;
    }
    // aplic F(2n) = F(n) * [2 * F(n + 1) - F(n)]
    c = (1ULL * a * c) % MOD;

    // aplic F(2n + 1) = F(n) ^ 2 + F(n + 1) ^ 2
    d = (1ULL * a * a + 1ULL * b * b) % MOD;

    if (n % 2 == 0) {  // pentru n par
        res[0] = c;
        res[1] = d;
    } else {  // pentru n impar
        res[0] = d;
        res[1] = c + d;
        if (res[1] >= MOD) {
          res[1] -= MOD;  // verificare continua ca nu am incredere
        }
    }
}

