      res = (1ULL * res * f[0]) % MOD;  // inmultesc cu rezultatul final
      // grija la % MOD
    } else if (c == 'u') {  // daca e u
      fib(nr + 1, f);  // la fel
      res = (1ULL * res * f[0]) % MOD;
      }
    }

    fin.close();
    ofstream fout(outfile);

    fout << res << endl;

    fout.close();
    return 0;
}

