		obj = new MyScanner(new FileReader("badgpt.in"));

		String sir = obj.nextLine();
		// un array 3D in care salvez cele 64 de matrici
		long[][][] valoriFibo;
		valoriFibo = calculeInitiale();
		long rezultat = 0;

		int cntParcurgere = 0;
		while (cntParcurgere < sir.length()) {
			String numar = "";
			// daca nu e 'n' sau 'u' ignoram
			if (sir.charAt(cntParcurgere) == 'n' || sir.charAt(cntParcurgere) == 'u') {
				cntParcurgere++;
				while (cntParcurgere < sir.length()
						&& (sir.charAt(cntParcurgere) >= '0' && sir.charAt(cntParcurgere) <= '9')) {
					numar += sir.charAt(cntParcurgere);
					cntParcurgere++;
				}
				// pentru primul numar doar atribui
				if (rezultat == 0) {
					rezultat = calculFibonacci(valoriFibo, Long.parseLong(numar)) % MOD;
				} else {
					// pentru celelalte numere inmultesc cu anterioarele
					rezultat = ((rezultat % MOD) * calculFibonacci(valoriFibo,
							Long.parseLong(numar)) % MOD) % MOD;
				}
				continue;
			}
			cntParcurgere++;
			// ignor cifrele literelor care nu sunt 'n' sau 'u'
			while (cntParcurgere < sir.length()
					&& (sir.charAt(cntParcurgere) >= '0' && sir.charAt(cntParcurgere) <= '9')) {
				cntParcurgere++;
			}
		}

		try (var printer = new PrintStream("badgpt.out")) {
			if (rezultat != 0) {
				printer.println(rezultat % MOD);
			} else {
				printer.println("1");
			}
		}

	}
}

