import java.util.StringTokenizer;

class Badgpt {

	static String input;
	static int MOD = 1000000007;
	static long MOD1 = 1000000007;
	static int KMAX =  3;
	static long answer = 1;
	static int[][] fibonacci = new int[KMAX][KMAX];

	static void fibo_matrix() {
		fibonacci[0][0] = 1;
		fibonacci[0][1] = 0;
		fibonacci[0][2] = 1;
		fibonacci[1][0] = 0;
		fibonacci[1][1] = 0;
		fibonacci[1][2] = 0;
		fibonacci[2][0] = 1;
		fibonacci[2][1] = 0;
		fibonacci[2][2] = 0;
	}

	// C = A * B
	static void multiply_matrix(int[][] A, int[][] B, int[][] C) {
		int[][] tmp = new int[KMAX][KMAX];

		for (int i = 0; i < KMAX; ++i) {
			for (int j = 0; j < KMAX; ++j) {
				long sum = 0;

				for (int k = 0; k < KMAX; ++k) {
					sum += 1L * A[i][k] * B[k][j];
				}

				tmp[i][j] = (int)(sum % MOD1);
			}
		}

		for (int i = 0 ; i < KMAX ; i++) {
			for (int j = 0 ; j < KMAX ; j++) {
				C[i][j] = tmp[i][j];
			}
		}

	}

	// R = C^p
	static void power_matrix(int[][] C, long p, int[][] R) {

		int[][] tmp = new int[KMAX][KMAX];
		for (int i = 0; i < KMAX; ++i) {
			for (int j = 0; j < KMAX; ++j) {
				tmp[i][j] = (i == j) ? 1 : 0;
			}
		}

		while (p != 1) {
			if  (p % 2 == 0) {
				multiply_matrix(C, C, C);
				p /= 2;
			} else {
				multiply_matrix(tmp, C, tmp);
				--p;
			}
		}

		multiply_matrix(C, tmp, R);
		System.out.println(R[0][0]);
	}

	static void read_and_resolve(char c, String input) {
		int index = input.indexOf(c);

		/*
		La aceasta problema m-am folosit strict de laboratul de programare dinamica
		prin care am calculat fibonacci pentru fiecare termen pe care l-am gasit, dupa
		care i-am inmultit intre ei pentru a afla toate posibilitatile.
		Acest algoritm de ridicare a matricii lui fibonacci a fost preluat din laborator
		pentru a fi cat mai eficient
