		while (index != -1) {
			int aux = 1;
			long number = 0;
			while ((index + aux != input.length())
					&& input.charAt(aux + index) >= '0' && input.charAt(aux + index) <= '9') {
				number = (number * 10 + (input.charAt(aux + index) - 48));
				aux++;
			}
			power_matrix(fibonacci, number, fibonacci);
			answer = ((answer % MOD) * (fibonacci[0][0] % MOD)) % MOD;
			index = input.indexOf(c,index + aux);
			fibo_matrix();
		}
