        #include <bits/stdc++.h>

using namespace std;

// Clasa pentru rezolvarea problemei BadGPT
class BadGPT {
 public:
    // Metoda care citeste datele de intrare, apeleaza metoda de rezolvare a
    // problemei si afiseaza rezultatul
    void solve() {
        read_input();
        print_output(get_results());
    }

 private:
    static constexpr int64_t MOD = 1000000007;
    static constexpr int DIM = 3;  // Dimensiunea matricelor
    string s;
    vector<int64_t> exp;
    // Metoda care citeste datele de intrare
    void read_input() {
        cin >> s;
        for (uint32_t i = 0; i < s.length(); ++i) {
            // Daca intalnim un 'n' sau 'u', parsam numarul din sir de carctere
            if (s[i] == 'n' || s[i] == 'u') {
                int64_t nr = 0;
                while (isdigit(s[++i])) {
                    nr = nr * 10 + (s[i] - '0');
                }
                --i;
                exp.push_back(nr);
            }
        }
    }
    // Metoda care afiseaza rezultatul
    void print_output(int64_t n) { cout << n; }
    // Metoda care calculeaza rezultatul
    int64_t get_results() {
        int64_t n = 1;
        // Pentru fiecare exponent in parte, calculam matricea fibonacci^n-2
        // pentru a afla al n-lea termen din sirul fibonacci in O(log n)
        for (auto& x : exp) {
            n *= calc(x);
            n %= MOD;
        }
        return n;
    }
    // Metoda care inmulteste doua matrici si salveaza rezultatul in prima
    // matrice
    void inmul_mat(int64_t a[DIM][DIM], int64_t b[DIM][DIM]) {
        int64_t c[DIM][DIM];
        for (int i = 0; i < DIM; ++i) {
            for (int j = 0; j < DIM; ++j) {
                auto sum = 0ULL;
                for (int k = 0; k < DIM; ++k) {
                    sum += 1LL * (a[i][k] * b[k][j]) % MOD;
                }
                c[i][j] = (sum % MOD);
            }
        }
        memmove(a, c, sizeof(c));
    }
    // Metoda care ridica la putere o matrice si returneaza al n-lea termen din
    // sirul fibonacci
    int64_t pow_mat(int64_t a[DIM][DIM], int64_t n) {
        int64_t I3[DIM][DIM] = {{1, 0, 0}, {0, 1, 0}, {0, 0, 1}};
        // Matricea identitate 3x3
        while (n != 1) {
            if (n % 2 == 1) {
                // Rezultat partial pentru cazul impar
                inmul_mat(I3, a);
                --n;
            } else {
                // Rezultat partial pentru cazul par
                inmul_mat(a, a);
                n /= 2;
            }
        }
        // Rezultatul final
        inmul_mat(a, I3);
        return (2 * a[0][0] + a[0][1]) % MOD;
    }
    // Metoda wrapper pentru ridicarea la putere a matricei fibonacci
    int64_t calc(int64_t n) {
        // Matricea fibonacci
        int64_t mat[DIM][DIM] = {{1, 1, 0}, {1, 0, 0}, {0, 1, 0}};
        return ((n <= 2) ? n : pow_mat(mat, n - 2) % MOD);
    }
};

