    // output
    freopen("badgpt.in", "r", stdin);
    freopen("badgpt.out", "w", stdout);
    // Cream un obiect de tip Feribot folosind pointer smart si apelam metoda
    // solve
    auto task = make_unique<BadGPT>();
    task->solve();
    return 0;
}

