 * Returns the result of multiplying c1 with c2
 * */
matrix multiply_2_matrix(const matrix &c1, const matrix &c2) {
    matrix sol;
    sol.first.first = ((c1.first.first * c2.first.first) % mod
                    + (c1.second.first * c2.first.second) % mod) % mod;
    sol.first.second = ((c1.first.second * c2.first.first) % mod
                    + (c1.second.second * c2.first.second) % mod) % mod;
    sol.second.first = ((c1.first.first * c2.second.first) % mod
                    + (c1.second.first * c2.second.second) % mod) % mod;
    sol.second.second = ((c1.first.second * c2.second.first) % mod
                    + (c1.second.second * c2.second.second) % mod) % mod;

    return sol;
}

/*
 * Returns matrix c to the power of n in logn time
 * */
matrix get_matrix(matrix &c, uint64_t n) {
    if (n == 1)
        return c;

    if (n == 2)
        return multiply_2_matrix(c, c);

    if (n % 2 == 0) {
        auto auxC = get_matrix(c, n/2);
        return multiply_2_matrix(auxC, auxC);
    } else {
        auto auxC = get_matrix(c, n/2);
        return multiply_2_matrix(multiply_2_matrix(auxC, auxC), c);
    }
}

/*
 * Returns the n-th number in fibonacci sequence
 * */
uint64_t get_fibo(uint64_t n) {
    if (n < 3)
        return n;

    // Initial state (S2) which is not needed because it is (1, 1)
    //    pair<uint64_t, uint64_t> s2;
    //    s2.first = s2.second = 1;

    // Init matrix C, where Si = Si-1 * C, and C = [(0, 1), (1, 1)]
    matrix C;
    C.first.first = 0;
    C.first.second = C.second.first = C.second.second = 1;

    // matrix Cn, where Cn = C^(n-2)
    matrix Cn = get_matrix(C, n - 2);

    // state sn, where sn = s2 * C^(n-2)
    pair<uint64_t, uint64_t> sn;
    sn.first = (Cn.first.first + Cn.first.second) % mod;
    sn.second = (Cn.second.first + Cn.second.second) % mod;

    return (sn.second + sn.first) % mod;
}

void manage_group(struct group &g, uint64_t &sol) {
    if (g.l != 'u' && g.l != 'n')
        return;

