	private static long solveTask1(long[] a,int ships) {
		long sum = 0;
		long max_elem = 0;
		long mijloc;
		for (int i = 0; i < a.length; i++) {
			sum += a[i];
			if (a[i] > max_elem) {
				max_elem = a[i]; 
			}			
		}
