using namespace std;

int main() {
    ifstream fin("feribot.in");
    ofstream fout("feribot.out");

    int N, K;
    fin >> N >> K;

    vector <long long> greutati(N);
    long long stanga = 0, dreapta = 0, mijloc;

    // variabila stanga retine cea mai mare greutate din lista de greutati
    // variabila dreapta retine suma tuturor greutatilor masinilor
    for (int i = 0; i < N; i++) {
        fin >> greutati[i];
        dreapta += greutati[i];
        if (greutati[i] > stanga)
            stanga = greutati[i];
    }

    // se foloseste cautarea binara pentru a determina costul minim
    // de traversare cerut
    while (stanga < dreapta) {
        // variabila folosita pentru a calcula, pe rand, greutatea transportata
        // de un feribot
        long long greutate_curenta = 0;

        // numarul de feriboturi utilizate
        int feribot = 1;

        // se simuleaza imbarcarea masinilor pentru a verifica daca
        // valoarea medie reprezinta costul de traversare
        mijloc = (stanga + dreapta) / 2;
        for (int i = 0; i < N; i++) {
            if (greutate_curenta + greutati[i] <= mijloc) {
                greutate_curenta += greutati[i];
            } else {
                feribot++;
                greutate_curenta = greutati[i];
            }
        }

        // daca nr de feriboturi e mai mare => costul este mai mare
        // decat cel presupus
        // daca nr de feriboturi e mai mic => costul este mai mic
        // decat cel presupus
        (feribot > K)? (stanga = mijloc + 1) : (dreapta = mijloc);
    }

    fout << stanga;

    return 0;
}

