        #include <cstdint>
#include <fstream>
#include <vector>

using namespace std;

long long
find_max(long long cars[], int n) {
    long long max = 0;

    for (int i = 0; i < n; ++i) {
        if (max < cars[i]) {
            max = cars[i];
        }
    }

    return max;
}

long long
find_sum(long long cars[], int n) {
    long long sum = 0;

    for (int i = 0; i < n; ++i) {
        sum += cars[i];
    }

    return sum;
}

long long
how_many_I_create(long long largest, long long cars[], int n) {
    long long sum = 0;
    long long res = 1;

    // create partitions where each partition reach
    // its limit to add less or equal
    // than largest
    for (int i = 0; i < n; ++i) {
        if (sum + cars[i] > largest) {
            res++;
            sum = cars[i];
            continue;
        }
        sum += cars[i];
    }

    // return the smallest number of partition needed
    return res;
}

bool
is_it_possible(long long largest, long long cars[],
long long subarrays, int n) {
    long long res = how_many_I_create(largest, cars, n);
    return (res <= subarrays);
}

long long
solve_task(int n , int k, long long cars[]) {
    // initiate extreme/edge cases
    long long left_limit = find_max(cars, n);
    long long rigth_limit = find_sum(cars, n);
    long long res = rigth_limit;

    // check if the best case can be done first to avoid nlogs complexity
    if (is_it_possible(left_limit, cars, k, n) == true) {
        return left_limit;
    }

    // binary search
    while (left_limit <= rigth_limit) {
        long long mid = left_limit + ((rigth_limit - left_limit) / 2);
        if (is_it_possible(mid, cars, k, n)) {
            res = mid;
            rigth_limit = mid - 1;
        } else {
            left_limit = mid + 1;
        }
    }
    return res;
}

int main() {
    ifstream fin("feribot.in");
    ofstream fout("feribot.out");

    int n, k;
    fin >> n;
    fin >> k;

    long long cars[n];
    long long aux;

    for (int i = 0; i < n; ++i) {
        fin >> aux;
        cars[i] = aux;
    }

    long long res = solve_task(n, k , cars);
    fout << res << "\n";

    return 0;
}

