        import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;


public class Feribot {

	public static long solve(int n, int k, long left, long right, long[] g) {
		long max = Long.MAX_VALUE;
		//cautare binara
		while (left < right) {
			long mid = (left + right) / 2;
			int tempk = k;
			long subsum = 0;
			boolean skip = false;
			for (int i = 0; i < n; i++) {
				/*daca depaseste greutatea maxima admisa
				nu poate fi incarcat*/
				if (g[i] > mid) {
					skip = true;
					break;
				}
				if (subsum + g[i] <= mid) {
					subsum += g[i];
				} else {
					tempk--;
					subsum = g[i];
				}
			}
			if (skip) {
				left = mid + 1;
				continue;
			}
			if (tempk >= 1) {
				max = mid;
				right = mid;
			} else {
				left = mid + 1;
			}
		}
		return max;
	}

	public static void main(String []args) throws IOException {
		Scanner scanner = new Scanner(new File("feribot.in"));
		int n, k;
		n = scanner.nextInt(); // nr masini
		k = scanner.nextInt(); // nr feriboturi
		long[] g = new long[n]; //greutatile masinilor
		long sumW = 0;
		for (int i = 0; i < n; i++) {
			g[i] = scanner.nextLong();
			sumW += g[i];
		}
		long left = sumW / k; //capatul din stanga
		long right = sumW; //capatul din dreapta
		long max = solve(n, k, left, right, g);
		FileWriter fWriter = new FileWriter("feribot.out");
		fWriter.write(String.valueOf(max));
		fWriter.close();
	}
}

