        /*
 * Acest schelet citește datele de intrare și scrie răspunsul generat de voi,
 * astfel că e suficient să completați cele două funcții.
 *
 * Scheletul este doar un punct de plecare, îl puteți modifica oricum doriți:
 * puteți schimba parametrii, reordona funcțiile etc.
 */

#include <cstdint>
#include <fstream>
#include <vector>
#include <algorithm>

using namespace std;

int64_t SolveTask1(const vector<int>& a, const vector<int>& b) {
    vector<int> c = a;
    c.insert(c.end(), b.begin(), b.end());

    // in c retin toate numerele ordonate
    sort(c.begin(), c.end());

    int64_t sum = 0;

    // am oricate miscari, pot sa aranjez listele astfel incat
    // cele mai mari n numere sa poata fi adunate
    for (int i = c.size()/2; i < c.size(); i++)
        sum += c[i];

    return sum;
}

int64_t SolveTask2(const vector<int>& a, const vector<int>& b, int moves) {
    int64_t sum = 0;

    // vector folosit pentru retinerea tuturor numerelor in ordine
    vector<int> c = a;
    c.insert(c.end(), b.begin(), b.end());
    sort(c.begin(), c.end());

    // cel mai mic numar din a doua jumatae a tuturor elementelor sortate
    int min_of_max = c[c.size() / 2];

    // retine maximele curente din cele 2 liste paralele
    vector<int> crt_max(a.size());

    // numarul de maxime pe care le avem deja
    int counter = 0;

    // vector unde se retin numerele din a doua jumatate a lui c
    // si care sunt mai mici decat un alt numar din aceeasi zona
    // practic, "ascunse" dupa cel mai mare
    vector<int> hidden_max;

    // aduag la suma maximele care sunt deja disponibile
    // si retin maximele "ascunse"
    for (int i = 0 ; i < a.size(); i++) {
        // completez lista de maxime curente
        crt_max[i] = max(a[i], b[i]);

        // retin maximele "ascunse"
        if (a[i] >= min_of_max && b[i] >= min_of_max)
            hidden_max.push_back(min(a[i], b[i]));

        // daca maximul curent exista in lista de maxime
        // este aduagat la suma
        if (crt_max[i] >= min_of_max) {
            sum += crt_max[i];
            counter ++;
        }
    }

    // sortez lista de maxime ascunse
    sort(hidden_max.begin(), hidden_max.end());

    int start = hidden_max.size() - 1;
    int end = hidden_max.size() - moves - 1;

    // "inlocuiesc" cele mai mari 'moves' maxime "ascunse"
    // practic, decat adun ultimele 'moves' numere din hidden_max
    for (int i = start; i > end; i--)
        sum += hidden_max[i];

    // maximele curente sunt sortate pentru a "inlocui" pe cel mai mic
    // maxim curent cu ultimul element din hidden_max
    sort(crt_max.begin(), crt_max.end());

    // am "inlocuit" primele 'moves' maxime din crt_max cu ultimele nr din
    // hidden_max, am adunat deja ultime 'counter' elemente, care erau din
    // cele maxime, au ramas de adunat maximele de la pozitia 'moves'
    // pana la a.size() - counter
    for (int i = moves; i < a.size() - counter; i++) {
        sum += crt_max[i];
    }

    return sum;
}

vector<int> ReadVector(istream& is, int size) {
    vector<int> vec(size);
    for (auto& num : vec) {
        is >> num;
    }
    return vec;
}

int main() {
    ifstream fin("nostory.in");
    ofstream fout("nostory.out");

    int task;
    fin >> task;

    int n, moves;
    if (task == 1) {
        fin >> n;
    } else {
        fin >> n >> moves;
    }

    auto a = ReadVector(fin, n);
    auto b = ReadVector(fin, n);

    auto res = task == 1 ? SolveTask1(a, b) : SolveTask2(a, b, moves);
    fout << res << "\n";

    return 0;
}

