int64_t SolveTask1(const vector<int>& a, const vector<int>& b) {
    int64_t score = 0;

    // retin in n lungimea lui a
    int n = a.size();

    // retin in aSorted elementele lui a
    vector<int>aSorted = a;
    // retin in bSorted elementele lui b
    vector<int>bSorted = b;

    // sortez crescator pe aSorted
    sort(aSorted.begin(), aSorted.end());
    // sortez descrescator pe bSorted
    sort(bSorted.rbegin(), bSorted.rend());

    // interschimb elementele celor 2 vectori,
