    int n = a.size();

    // retin in aSorted elementele lui a
    vector<int>aSorted = a;
    // retin in bSorted elementele lui b
    vector<int>bSorted = b;

    // pastrez in aSorted cele mai mari elemente
    for (int i = 0; i < n; i++) {
        if (aSorted[i] < bSorted[i]) {
            swap(aSorted[i], bSorted[i]);
