class Semnale {

	static int sig_type, x, y;
	static final int  mod = 1000000007;

	Semnale(){}

	static int type1() {
		int [][]matrix = new int[x + 1][y + 1];

		for (int[] row: matrix) {
			Arrays.fill(row, -1);
		}

		Arrays.fill(matrix[0], 0);

		matrix[0][1] = 1;
		for (int i = 0; i <= x; i++) {
			matrix[i][0] = 1;
		}

		matrixBuildTypeOne(matrix, x, y);

		return matrix[x][y];
	}

	public static void matrixBuildTypeOne(int [][]matrix, int a, int b) {
		if (matrix[a][b] == -1) {
			if (matrix[a - 1][b] == -1) {
				matrixBuildTypeOne(matrix, a - 1, b);
			}

			if (matrix[a - 1][b - 1] == -1) {
				matrixBuildTypeOne(matrix, a - 1, b - 1);
			}

			matrix[a][b] = (matrix[a - 1][b] + matrix[a - 1][b - 1]) % mod;
		}
	}

	static int type2() {

		int [][]matrix = new int[x + 1][y + 1];

		for (int[] row: matrix) {
			Arrays.fill(row, -1);
		}

		Arrays.fill(matrix[0], 0);

		matrix[0][2] = 1;
		for (int i = 0; i <= x; i++) {
			matrix[i][0] = 1;
			matrix[i][1] = i + 1;
		}

		matrixBuildTypeTwo(matrix, x, y);

		return matrix[x][y];
	}

	public static void matrixBuildTypeTwo(int [][]matrix, int a, int b) {
		if (matrix[a][b] == -1) {
			if (matrix[a - 1][b] == -1) {
				matrixBuildTypeTwo(matrix, a - 1, b);
			}

			if (matrix[a - 1][b - 1] == -1) {
				matrixBuildTypeTwo(matrix, a - 1, b - 1);
			}

			if (matrix[a - 1][b - 2] == -1) {
				matrixBuildTypeTwo(matrix, a - 1, b - 2);
			}

			matrix[a][b] = ((matrix[a - 1][b] + matrix[a - 1][b - 1]) % mod
					+ matrix[a - 1][b - 2]) % mod;
		}
	}

