				for (int k = 1; k <= 2; k++) {
					if (j >= k) {
						zero[i][j] = (zero[i][j] + one[i][j - k]) % mod;
					}
				}
			}
		}
		return ((one[x][y] + zero[x][y]) % mod);
	}

