using namespace std;

const int mod = 1000000007;

/* Calcul n! */
int factorial_modulo(int n) {
	unsigned long long result = 1;
	for (int i = 1; i <= n; i++) {
		result = (result * i) % mod;
	}
	return (int)result;
}

/* Triunghiul lui Pascal */
int type1(int zeros, int ones) {
	/* Daca numarul de 1 este prea mare, returneaza 0. */
	if (ones > zeros) {
		return 0;
	}
	/* Daca este vreun capat unde combinarea da 1, returneaza direct 1. */
	if (ones == 0 || ones == zeros) {
		return 1;
	} else {
		/* Combinari: n!/((n - k)! * k!) */
		unsigned long long num = factorial_modulo(zeros);
		unsigned long long den = ((long long)1 * factorial_modulo(ones) *
								  factorial_modulo(zeros - ones)) % mod;
		unsigned long long invden = 1;
		/* Teorema lui Fermat: (a^p) % mod = a^(p-1) % mod * a % mod*/
		unsigned long long power = 1000000005;
		while (power > 0) {
			/* Calculam inversul folosind mai putini pasi prin mica teorema a
			 lui Fermat. Ne folosim de o putere mare, iar la pas impar inmultim
			 si retinem valoarea. */
			if (power % 2) {
				invden = ((long long)1 * invden * den) % mod;
			}
			power /= 2;
			/* La fiecare pas inmultim si retinem in den pentru a micsora. */
			den = ((long long)1 * den * den) % mod;
		}
		/* Returnam rezultatul in functie de inversul calculat care acum evita
		 overflow-ul. */
		return ((long long)1 * num * invden) % mod;
	}
}

int type2(int zeros, int ones) {
	/* Daca sunt mult prea multi de 1, returnam 0. */
	if (ones > zeros * 2 + 2)  {
		return 0;
	}
	/* Daca avem un singur 1 sau 2 * nr_zero + 1, returnam nr_zero + 1
	 (este in oglinda ca la combinari).*/
	if (ones == zeros * 2 + 1 || ones == 1) {
		return zeros + 1;
	}
	/* Daca avem suficienti de 1 cat sa ii punem unul langa altul si sa
	 respectam relatia complet, atunci eturneaza 1(o singura varianta).*/
	if (ones == zeros * 2 + 2) {
		return 1;
	}
	/* Daca numarul de unu depaseste jumatatea superioara, micsoram. (este
	 egal cu oglinditul sau). */
	if (ones > zeros + 1) {
		ones = 2 * (zeros + 1) - ones;
	}
	/* Cream matricea care va stoca elementele. */
	vector<vector<unsigned long long>> aux(zeros + 10,
										   vector<unsigned long long>
										   (zeros * 2 + 10));
	aux[0][1] = 1;
	aux[0][2] = 1;
	for (int i = 1; i <= zeros; i++) {
		/* Primul element este este numarul liniei curente + 1, iar al doilea
		 element este suma primului element cu elementul de deasupra sa. */
		aux[i][1] = (i + 1) % mod;
		aux[i][2] = (aux[i][1] + aux[i - 1][2]) % mod;
		/* Daca sunt mai putine coloane valabile decat numarul de 1 necesar
		 intram pe aceasta ramura. */
		if (2 * i - 2 < ones) {
			/* Elementul curent este egal cu suma celor 3 elemente de deasupra
			 sa precedente: pe aceeasi coloana cu el, col-1 si col-2. */
			for (int j = 3; j <= 2 * i; j++) {
				aux[i][j] = ((aux[i - 1][j - 2] +
							  aux[i - 1][j - 1]) % mod + aux[i - 1][j]) % mod;
			}
			/* Penultimul element este egal cu primul, iar ultimul cu 1
			 (singura) posibilitate. */
			aux[i][2 * i + 1] = aux[i][1];
			aux[i][2 * i + 2] = 1;
		} else {
			for (int j = 3; j <= ones; j++) {
				aux[i][j] = ((aux[i - 1][j - 2] +
							  aux[i - 1][j - 1]) % mod + aux[i - 1][j]) % mod;
			}
		}
	}
	return aux[zeros][ones] % mod;
}

