	for (int i = 1; i <= x; i++) {
		// iteram prin valorile de 1
		for (int j = 1; j <= i && j <= y; j++) {
			// recurenta:
			// dp(i,j) = dp(i-1, j-1) + dp(i - 1)(j)
			dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j];

			// rezultatul il trecem ca restun imaprtirii la mod
			// deoarece putem avea solutii prea mari
			dp[i][j] %= mod;
		}
	}

	// intoarcem numarul de combinari de x 0 si y 1
	return dp[x][y] % mod;
}

int computeSignals2(int x, int y) {
	// returnam 0 daca numarul de valori de 1 este
	// mai mare decat numarul de valori de 0 + 1 ori
	// doi deoarece astfel de semnale nu pot fii formate

	if ((x + 1) * 2 < y) {
		return 0;
	}

	// creem o matrice de x + 1 linii (valorile posibile de 0)
	// si y + 1 coloane (valorile posibile de 1)
	vector<vector<uint64_t>> dp(x + 1, vector<uint64_t>(y + 1, 0));

	// primele 3 elemente de pe linia 0 devin 1
	// cazul de baza
	for (int i = 0; i < 3; i++) {
		dp[0][i] = 1;
	}

	// elementele de pe prima coloana devin 1
	for (int i = 0; i <= x; i++) {
		dp[i][0] = 1;
	}

	// iteram prin valorile de 0
	for (int i = 1; i <= x; i++) {
		// iteram prin valoriel de 1
		for (int j = 1; j <= (i + 1) * 2 && j <= y; j++) {
			// daca elementul de afla pe coloana 1
			// dp[i][j] = dp[i - 1][j] + dp[i - 1][j - 1]
			if (j == 1) {
				dp[i][j] = dp[i - 1][j] + dp[i - 1][j - 1];
				dp[i][j] %= mod;
			} else {
				// daca nu:
				//  dp[i][j] = dp[i - 1][j-1] + dp[i - 1][j] + dp[i - 1][j - 2]
				dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j] + dp[i - 1][j - 2];
				dp[i][j] %= mod;
			}
		}
	}

	return dp[x][y] % mod;
}

int type1(int x, int y) {
	int ans = computeSignals1(x, y);
	return ans;
}

int type2(int x, int y) {
	return computeSignals2(x, y);
}

int main() {
	freopen("semnale.in", "r", stdin);
	freopen("semnale.out", "w", stdout);

	int sig_type, x, y;

	cin >> sig_type >> x >> y;

	switch (sig_type) {
	case 1:
		cout << type1(x, y);
		break;
	case 2:
		cout << type2(x, y);
		break;
	default:
		cout << "wrong task number" << endl;
	}

	return 0;
}

