public class Sushi {

	static int n, m, x;
	static int[] prices;
	static int[][] grades;

	static int[] totalGrades;

	Sushi() {
	}

	static int task1() {
		int maxSum = n * x;
		int[] dp = new int[maxSum + 1];

		// i reprezinta primele i platouri considerate la solutie
		for (int i = 1; i <= m; i++) {
			for (int j = maxSum; j >= prices[i - 1]; j--) {
				dp[j] = Math.max(dp[j], dp[j - prices[i - 1]]
						+ totalGrades[i - 1]);
			}
		}

		return dp[maxSum];
	}

	static int task2() {
		int maxSum = n * x;
		int[][] dp = new int[m + 1][maxSum + 1];

		// i reprezinta primele i platouri considerate la solutie
		// j reprezinta suma maxima pe care o poti cheltui luand
		// in considerare primele i platouri
		for (int i = 1; i <= m; i++) {
			for (int j = 0; j <= maxSum; j++) {
				dp[i][j] = dp[i - 1][j];

				if (prices[i - 1] <= j) {
					int potentialBetter = dp[i - 1][j - prices[i - 1]]
							+ totalGrades[i - 1];
					dp[i][j] = Math.max(dp[i][j], potentialBetter);
				}

				if (2 * prices[i - 1] <= j) {
					int potentialBetter = dp[i - 1][j - 2 * prices[i - 1]]
							+ 2 * totalGrades[i - 1];
					dp[i][j] = Math.max(dp[i][j], potentialBetter);
				}
			}
		}

		return dp[m][maxSum];
	}

	static int task3() {
		int maxSum = n * x;
		int[][][] dp = new int[m + 1][maxSum + 1][n + 1];

		// i reprezinta primele i platouri considerate la solutie
		// j reprezinta suma maxima pe care o poti cheltui luand
		// in considerare primele i platouri
		// k reprezinta numarul de platuri selectate
		for (int i = 1; i <= m; i++) {
			for (int j = 0; j <= maxSum; j++) {
				for (int k = 0; k <= n; k++) {
					dp[i][j][k] = dp[i - 1][j][k];

					if (prices[i - 1] <= j && k >= 1) {
						int better = dp[i - 1][j - prices[i - 1]][k - 1]
								+ totalGrades[i - 1];
						dp[i][j][k] = Math.max(dp[i][j][k], better);
					}

					if (2 * prices[i - 1] <= j && k >= 2) {
						int better = dp[i - 1][j - 2 * prices[i - 1]][k - 2]
								+ 2 * totalGrades[i - 1];
						dp[i][j][k] = Math.max(dp[i][j][k], better);
					}
				}
			}
		}

		return dp[m][maxSum][n];
	}

