    for (int cap = 1; cap <= n * x; ++cap) {
      if (cap - p[i - 1] >= 0) {
        int sol_aux = dp[i - 1][cap - p[i - 1]] + note[i - 1];
        dp[i][cap] = max(dp[i - 1][cap], sol_aux);
      } else {
        dp[i][cap] = dp[i - 1][cap];
      }
    }
  }

  return dp[m][n * x];
}

