        import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

public class Sushi {
	static int n, m, b;
	static int[] prices;
	static int[] sumGrades;

	Sushi(){}

	/*
	 * Create dp bidimensional array for tasks 1 and 2
	 * Made with the help of laboratory implementation for backpack problem
	 * https://ocw.cs.pub.ro/courses/pa/laboratoare/laborator-03#rezolvare2
	 */
	private static int createDp(int plates) {
		int[][] dp = new int[plates + 1][b + 1];

		/* Current sushi plate */
		for (int i = 1; i <= plates; i++) {
			/* Current budget */
			for (int p = 1; p <= b; p++) {
				/* If I don't get to use the current plate, use previous solution */
				dp[i][p] = dp[i - 1][p];

				/* Compute the index so that I don't have to duplicate the prices and
				   grades arrays */
				int idx = i % (m + 1);

				/* If the price stays in budget, consider this solution */
				if (p - prices[idx] >= 0) {
					/* Get the best 'deal' */
					int aux = dp[i - 1][p - prices[idx]] + sumGrades[idx];
					dp[i][p] = Math.max(dp[i][p], aux);
				}
			}
		}

		return dp[plates][b];
	}

	static int task1() {
		return createDp(m);
	}

	static int task2() {
		return createDp(2 * m);
	}

	static int task3() {
		int plates = 2 * m;
		int[][][] dp = new int[plates + 1][b + 1][n + 1];

		/* Current sushi plate */
		for (int i = 1; i <= plates; i++) {
			/* Current budget */
			for (int p = 1; p <= b; p++) {
				/* Number of chosen plates */
				for (int k = 1; k <= n; k++) {
					/* If I don't get to use the current plate, use previous solution */
					dp[i][p][k] = dp[i - 1][p][k];

					/* Compute the index so that I don't have to duplicate the prices and
				   	   grades arrays */
					int idx = i % m + 1;

					/* If the price stays in budget, consider this solution */
					if (p - prices[idx] >= 0) {
						int aux = dp[i - 1][p - prices[idx]][k - 1] + sumGrades[idx];
						dp[i][p][k] = Math.max(dp[i][p][k], aux);
					}
				}
			}
		}

		return dp[plates][b][n];
	}

	public static void main(String[] args) {
		try {
			Scanner sc = new Scanner(new File("sushi.in"));
			final int task = sc.nextInt();

			/* Number of friends */
			n = sc.nextInt();

			/* Number of sushi types */
			m = sc.nextInt();

			/* How much each of you is willing to spend */
			int x = sc.nextInt();
			b = n * x;

			prices = new int[m + 1];
			sumGrades = new int[m + 1];

			for (int i = 1; i <= m; ++i) {
				prices[i] = sc.nextInt();
			}

			for (int i = 0; i < n; i++) {
				for (int j = 0; j < m; j++) {
					/* Compute the sum of the grades */
					sumGrades[j + 1] += sc.nextInt();
				}
			}

			int ans;
			switch (task) {
				case 1:
					ans = Sushi.task1();
					break;
				case 2:
					ans = Sushi.task2();
					break;
				case 3:
					ans = Sushi.task3();
					break;
				default:
					ans = -1;
					System.out.println("wrong task number");
			}

			try {
				FileWriter fw = new FileWriter("sushi.out");
				fw.write(Integer.toString(ans) + '\n');
				fw.close();

			} catch (IOException e) {
				System.out.println(e.getMessage());
			}

			sc.close();
		} catch (FileNotFoundException e) {
			System.out.println(e.getMessage());
		}
	}
}

