#include <vector>

using namespace std;

int task1(int n, int m, int x, const vector<int> &p,
		  const vector<int> &gradesSum) {
	x *= n;

	// knapsack
	vector<int> dp(x + 1, 0);
	for (int i = 0; i < m; i++) {
		for (int j = x; j >= p[i]; j--) {
			dp[j] = max(dp[j], dp[j - p[i]] + gradesSum[i]);
		}
	}

	return dp[x];
}

int task2(int n, int m, int x, vector<int> &p, vector<int> &gradesSum) {
	vector<int> doubleGrades(m * 2, 0);
	vector<int> doublePrices(m * 2, 0);

	for (int i = 0; i < m; i++) {
		doubleGrades[i] = gradesSum[i];
		doubleGrades[i + m] = gradesSum[i];
	}

	for (int i = 0; i < m; i++) {
		doublePrices[i] = p[i];
		doublePrices[i + m] = p[i];
	}

	return task1(n, m * 2, x, doublePrices, doubleGrades);
}

int task3(int n, int m, int x, vector<int> &p, vector<int> &gradesSum) {
	vector<int> doubleGrades(m * 2, 0);
	vector<int> doublePrices(m * 2, 0);

	for (int i = 0; i < m; i++) {
		doubleGrades[i] = gradesSum[i];
		doubleGrades[i + m] = gradesSum[i];
	}

	for (int i = 0; i < m; i++) {
		doublePrices[i] = p[i];
		doublePrices[i + m] = p[i];
	}

	m *= 2;
	x *= n;

	vector<vector<vector<int>>> dp(m + 1,
								   vector<vector<int>>(x + 1, vector<int>(n + 1, 0)));
	for (int i = 1; i <= m; i++) {
		for (int j = 1; j <= x; j++) {
			for (int k = 1; k <= n; k++) {
				if (doublePrices[i - 1] > j) {
					// current sushi plate cannot be added
					dp[i][j][k] = dp[i - 1][j][k];
				} else {
					// choose whether to add the current sushi plate or not
					dp[i][j][k] = max(dp[i - 1][j][k],
									  dp[i - 1][j - doublePrices[i - 1]][k - 1] + doubleGrades[i - 1]);
				}
			}
		}
	}
	return dp[m][x][n];
}

