	int m;
	int x;

	vector<int> prices;
	vector<vector<int>> grades;

	cin >> task;
	cin >> n >> m >> x;

	prices.assign(m, 0);
	grades.assign(n, vector<int>(m, 0));

	// price of each sushi
	for (int i = 0; i < m; ++i) {
		cin >> prices[i];
	}

	// each friends rankings of sushi types
	for (int i = 0; i < n; ++i) {
		for (int j = 0; j < m; ++j) {
			cin >> grades[i][j];
		}
	}

	int ans = -1;

	vector<int> gradesSum(m, 0);
	for (int i = 0; i < m; i++) {
		for (int j = 0; j < n; j++) {
			gradesSum[i] += grades[j][i];
		}
	}

	switch (task) {
	case 1:
		ans = task1(n, m, x, prices, gradesSum);
		break;
	case 2:
		ans = task2(n, m, x, prices, gradesSum);
		break;
	case 3:
		ans = task3(n, m, x, prices, gradesSum);
		break;
	default:
		cout << "wrong task number" << endl;
	}

	cout << ans << endl;

	return 0;
}

