using namespace std;
#define max_cols 10000

int
max_between(int a, int b) {
	if (a > b)
		return a;
	return b;
}

// top-down approach
int
find_task1_rec(int obj_index, int capital,
			vector<int> &prices, vector<int> &grades, int *dp[]) {
	if (obj_index <= 0) {
		return 0;
	}
	if (dp[obj_index][capital] != -1) {
		return dp[obj_index][capital];
	}
	if (capital < prices[obj_index - 1]) {
		dp[obj_index][capital] = find_task1_rec
		(obj_index - 1, capital, prices, grades, dp);
		return dp[obj_index][capital];
	}
	dp[obj_index][capital] = max_between(find_task1_rec
							(obj_index - 1, capital, prices, grades, dp),
							grades[obj_index - 1] + find_task1_rec
							(obj_index - 1, capital - prices[obj_index - 1],
							prices, grades, dp));
	return dp[obj_index][capital];
}

int task1(int n, int m, int x, vector <int>& p, vector <vector <int> >& g) {
	// p => price, g => grades, n - number of friends, m - number of sushi
	// type, x => money each of friends
	int sum_allocated = x * n;

	// calculate grade
	vector <int> total_grade;
	for (int i = 0; i < m; ++i) {
		int sum = 0;
		for (int j = 0; j < n; ++j) {
			sum += g[j][i];
		}
		total_grade.push_back(sum);
	}

	// init the matrix
	int *dp[m + 1];
	for (int i = 0; i <= m; ++i) {
		dp[i] = new int[sum_allocated + 1];
	}

	for (int i = 0; i <= m; ++i) {
		for (int j = 0; j <= sum_allocated; ++j) {
			dp[i][j] = -1;
		}
	}
	int a = find_task1_rec(m, sum_allocated, p, total_grade, dp);
	return a;
}

int task2(int n, int m, int x, vector <int> &p, vector <vector <int> > &g) {
	int sum_allocated = x * n;

