	// init matrix
	int *dp[2 * m + 1];

	for (int i = 0; i <= 2 * m; ++i) {
		dp[i] = new int[sum_allocated + 1];
	}

	for (int i = 0; i <= 2 * m; ++i) {
		for (int j = 0; j <= sum_allocated; ++j) {
			dp[i][j] = -1;
		}
	}

	int a = find_task1_rec(2 * m, sum_allocated,
	prices_for_task2, total_grade_for_task2, dp);

	return a;
}

int task3(int n, int m, int x, vector <int> &p, vector <vector <int> > &g) {
	int sum_allocated = x * n;
	vector <int> total_grade;

	// calculate total grade
	for (int i = 0; i < m; ++i) {
		int sum = 0;
		for (int j = 0; j < n; ++j) {
			sum += g[j][i];
		}
		total_grade.push_back(sum);
	}

	// double everything and copy 2 times
	vector<int> total_grade_for_task3;
	for (int i = 0; i < 2; ++i) {
		for (int j = 0; j < total_grade.size(); ++j) {
			total_grade_for_task3.push_back(total_grade[j]);
		}
	}

	vector<int> prices_for_task3;

	for (int i = 0; i < 2; ++i) {
		for (int j = 0; j < p.size(); ++j) {
			prices_for_task3.push_back(p[j]);
		}
	}

	// init 3D matrix
	vector<vector<vector<int>>> dp;
	dp.assign(m + 1,
			vector<vector<int>>(sum_allocated + 1,
			vector<int>(n + 1, 0)));

	// bottom-up approach this time
	for (int i = 1; i <= m; ++i) {
		for (int j = 1; j <= sum_allocated; ++j) {
			for (int k = 1; k <= n; ++k) {
				dp[i][j][k] = dp[i - 1][j][k];
				if (j - p[i - 1] >= 0) {
					if (dp[i - 1][j - p[i - 1]][k - 1]
					+ total_grade[i - 1] > dp[i][j][k]) {
						dp[i][j][k] =
						dp[i - 1][j - p[i - 1]][k - 1] +
						total_grade[i - 1];
					}
				}
				if (j >= (p[i - 1] + p[i - 1]) && i >= 1 && k >= 2) {
					if (dp[i][j][k] <
						dp[i - 1][j - p[i - 1] - p[i - 1]][k - 2] + 2 * total_grade[i - 1]) {
							dp[i][j][k] =
							dp[i - 1][j - p[i - 1] - p[i - 1]][k - 2] + 2 * total_grade[i - 1];
						}
				}
			}
		}
	}

	return dp[m][sum_allocated][n];
}

