import java.io.BufferedReader;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Stack;


public class Ferate {
	static ArrayList<Integer>[] adj;
	static ArrayList<Integer>[] revAdj;
	static boolean[] visited;
	static Stack<Integer> stack;
	static int[] component;
	static int componentsCount;
	static ArrayList<Integer>[] componentAdj;

	public static void main(String[] args) {
		try {
			BufferedReader reader = new BufferedReader(new FileReader("ferate.in"));

			String[] line = reader.readLine().split(" ");
			int n = Integer.parseInt(line[0]);
			int m = Integer.parseInt(line[1]);
			int s = Integer.parseInt(line[2]);

			adj = new ArrayList[n + 1];
			revAdj = new ArrayList[n + 1];
			visited = new boolean[n + 1];
			stack = new Stack<>();
			component = new int[n + 1];
			componentsCount = 0;

			for (int i = 1; i <= n; i++) {
				adj[i] = new ArrayList<>();
				revAdj[i] = new ArrayList<>();
			}

			for (int i = 0; i < m; i++) {
				line = reader.readLine().split(" ");
				int u = Integer.parseInt(line[0]);
				int v = Integer.parseInt(line[1]);
				adj[u].add(v);
				revAdj[v].add(u);
			}

			for (int i = 1; i <= n; i++) {
				if (!visited[i]) {
					dfs1(i);
				}
			}

			visited = new boolean[n + 1];
			componentAdj = new ArrayList[n + 1];

			while (!stack.isEmpty()) {
				int node = stack.pop();
				if (!visited[node]) {
					componentsCount++;
					dfs2(node);
				}
			}

			for (int i = 1; i <= n; i++) {
				for (int v : adj[i]) {
					if (component[i] != component[v]) {
						componentAdj[component[i]].add(component[v]);
					}
				}
			}

			int linesToAdd = 0;
			boolean[] hasOutgoingEdge = new boolean[componentsCount + 1];
			for (int i = 1; i <= componentsCount; i++) {
				for (int v : componentAdj[i]) {
					hasOutgoingEdge[v] = true;
				}
			}
			for (int i = 1; i <= componentsCount; i++) {
				if (i != component[s] && !hasOutgoingEdge[i]) {
					linesToAdd++;
				}
			}

			System.out.println(linesToAdd);

			try {
				FileWriter out = new FileWriter("ferate.out");
				int result = linesToAdd;
				out.write(result + "");
				out.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}

		} catch (FileNotFoundException e) {
			throw new RuntimeException(e);
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	static void dfs1(int node) {
		visited[node] = true;
		for (int v : adj[node]) {
			if (!visited[v]) {
				dfs1(v);
			}
		}
		stack.push(node);
	}

	static void dfs2(int node) {
		visited[node] = true;
		component[node] = componentsCount;
		if (componentAdj[componentsCount] == null) {
			componentAdj[componentsCount] = new ArrayList<>();
		}
		for (int v : revAdj[node]) {
			if (!visited[v]) {
				dfs2(v);
			}
		}
	}
}

