				String[] line = br.readLine().split(" ");
				n = Integer.parseInt(line[0]);
				m = Integer.parseInt(line[1]);
				s = Integer.parseInt(line[2]);

				for (int i = 0; i <= n; i++) {
					adj.add(new ArrayList<>());
					adj2.add(new ArrayList<>());
				}
				indegree = new int[n + 1];
				for (int i = 0; i < m; i++) {
					line = br.readLine().split(" ");
					int x = Integer.parseInt(line[0]);
					int y = Integer.parseInt(line[1]);
					adj.get(x).add(y);
					adj2.get(y).add(x);
					indegree[y]++;
				}
				br.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput() {
			try {
				PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(OUTPUT_FILE)));
				pw.println(nr);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void getResult() {
			tarjanScc();
		}

		private void tarjanScc() {
			parent = new int[n + 1];
			found = new int[n + 1];
			low_link = new int[n + 1];
			in_stack = new boolean[n + 1];

			Arrays.fill(parent, -1);
			Arrays.fill(found, -1);
			Arrays.fill(low_link, -1);
			Arrays.fill(in_stack, false);

			timestamp = 0;
			for (int node = 1; node <= n; ++node) {
				if (parent[node] == -1) {
					parent[node] = node;
					dfs(node);
				}
			}
		}

		private void dfs(int node) {
			found[node] = ++timestamp;
			low_link[node] = found[node];
			nodes_stack.push(node);
			in_stack[node] = true;

			for (int neigh : adj.get(node)) {
				if (parent[neigh] != -1) {
					if (in_stack[neigh]) {
						low_link[node] = Math.min(low_link[node], found[neigh]);
					}
					continue;
				}
				parent[neigh] = node;
				dfs(neigh);
				low_link[node] = Math.min(low_link[node], low_link[neigh]);
			}

			if (low_link[node] == found[node]) {
				boolean sourceFound = false;
				List<Integer> scc = new ArrayList<>();
				do {
					int x = nodes_stack.peek();
					nodes_stack.pop();
					if (x == s) {
						sourceFound = true;
					}
					in_stack[x] = false;
					scc.add(x);
				} while (scc.get(scc.size() - 1) != node);

				if (!sourceFound) {
					if (scc.size() == 1 && indegree[scc.get(0)] == 0) {
						nr++;
					} else {
						boolean found0 = false;
						for (int i = 0; i < scc.size(); i++) {
							for (int j = 0; j < adj2.get(scc.get(i)).size(); j++) {
								if (!scc.contains(adj2.get(scc.get(i)).get(j))) {
									found0 = true;
									break;
								}
							}
							if (found0) {
								break;
							}
						}
						if (!found0) {
							nr++;
						}
					}
				}
			}
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}
