        #include <iostream>
#include <vector>
#include <fstream>
#include <algorithm>

using namespace std;
#define NUM 100005

// dfs algorithm
int dfs_explore(int node, int delivery, vector<bool>& visited,
    vector<vector<int>>& stores, vector<int>& order,
        vector<int>& start_pos, vector<int>& subtree_end) {
    visited[node] = true;
    delivery++;

    // 'setam' pozitia de inceput a nodului curent
    start_pos[node] = delivery;

    // adaug nodul la lista ordonata
    order[delivery] = node;

    // parcurgem toti vecinii nodului currnet
    for (int n : stores[node]) {
        if (!visited[n])
            delivery = dfs_explore(n, delivery, visited,
            stores, order, start_pos, subtree_end);
    }

    // 'setam' ultimul index al ultimului nod
    // al subgrafului nodului curent
    subtree_end[node] = delivery;
    return delivery;
}

int main() {
    ifstream fin("magazin.in");
    ofstream fout("magazin.out");

    int N, Q, X;
    fin >> N >> Q;

    vector<vector<int>> stores(NUM);
    vector<int> order(NUM);
    vector<int> start_pos(NUM);
    vector<int> subtree_end(NUM);
    vector<bool> visited(N + 1, false);

    for (int i = 2; i <= N; i++) {
        fin >> X;
        stores[X].push_back(i);
    }

    // dfs de la primul nod
    int delivery = 0;
    dfs_explore(1, delivery, visited, stores, order, start_pos, subtree_end);

    int E, D;
    for (int i = 0; i < Q; i++) {
        fin >> E >> D;
        // daca magazinul e o parte a subarborelui nodului curent
        // si e in range-ul livrarilor
        int look_up_store = start_pos[E] + D;
        if (look_up_store  <= subtree_end[E])
            // afisam nodul respectiv
            fout << order[look_up_store] << "\n";
        else
            fout << "-1\n";
    }

    fin.close();
    fout.close();
    return 0;
}

