	static int nr_taskuri;
	static int nr_dependente;
	static int[] g;
	static ArrayList<Integer>[] adj;
	static int[] in_degree;

	static int getResult() {
		// daca nu exista dependente nu se face nciun switch
		if (nr_dependente == 0) {
			return 0;
		}

		int[] dp = new int[nr_taskuri + 1];
		Arrays.fill(dp, 0);

		// adaugam intr-o coada taskurile fara grad intern
		Queue<Integer> queue = new LinkedList<>();
		for (int i = 1; i <= nr_taskuri; i++) {
			if (in_degree[i] == 0) {
				queue.add(i);
			}
		}

		// efectuam un bfs
		while (!queue.isEmpty()) {
			int node = queue.poll();

			// parcurgem nodurile din lista de adiacenta a nodului curent
			for (int neighbor : adj[node]) {
				in_degree[neighbor]--;

				// verificam daca au fost parcursi toti vecinii
				if (in_degree[neighbor] == 0) {
					queue.add(neighbor);
				}

				// verificam daca are loc un context switch
				if (g[node] != g[neighbor]) {
					// updatam numarul de context switchuri pentru fiecare nod	
					dp[neighbor] = Math.max(dp[neighbor], dp[node] + 1);
				} else {
					dp[neighbor] = Math.max(dp[neighbor], dp[node]);
				}
			}
		}

		int ans = 0;
		// alegem cel mai mic numar de context switchuri
		// dar care sa treaca prin toate nodurile
		for (int i = 1; i <= nr_taskuri; i++) {
			ans = Math.max(ans, dp[i]);
		}
		return ans;
	}

