			MyScanner sc = new MyScanner(new FileReader("supercomputer.in"));

			// salvam datele de intrare
			nr_taskuri = sc.nextInt();
			nr_dependente = sc.nextInt();

			g = new int[nr_taskuri + 1];
			adj = new ArrayList[nr_taskuri + 1];
			in_degree = new int[nr_taskuri + 1];
			Arrays.fill(in_degree, 0);

			// facem listele de adiacenta
			for (int i = 1; i <= nr_taskuri; i++) {
				g[i] = sc.nextInt();
				adj[i] = new ArrayList<>();
			}

			// salvam listele de adiacenta
			for (int i = 0; i < nr_dependente; i++) {
				int x = sc.nextInt();
				int y = sc.nextInt();
				adj[x].add(y);
				in_degree[y]++;
			}

			//sc.close();
			int ans;
			ans = Supercomputer.getResult();
			try {
