using namespace std;

long long mod = 1000000007;

int power(unsigned long long base, int exponent) {
    unsigned long long result = 1;
    while (exponent > 0) {
        if (exponent & 1)
            result = (result * base) % mod;

        exponent >>= 1;
        base = (base * base) % mod;
    }
    return result;
}

