    if (type == 'H') {
        result = (6ULL * power(3, --count)) % mod;
    } else {
        result = (3ULL * power(2, --count)) % mod;
    }

    for (int i = 1; i < n; i++) {
        char newType;
        input >> count >> newType;
        if (newType == 'H') {
            if (type == 'H') {
                result = (result * power(3, count)) % mod;
            } else {
                result = (2ULL * result) % mod;
                result = (result * power(3, --count)) % mod;
            }
        } else {
            if (type == 'H') {
                result = (result * power(2, --count)) % mod;
            } else {
                result = (result * power(2, count)) % mod;
            }
        }

