					// (Aranjamente de 3 luate cate 1), apoi urmatoarele zone verticale
					// pot genera fiecare doar cate 2 moduri dfierite de colorare,
					// deoarece sunt restrictionate de zona anterioara
					result = 3L * montgomery(2, number - 1);
