vector<int> find_sume_partiale(const vector<int>& nums) {
    vector<int> prefixSums(nums.size());  // Resize vector to the size of nums
    if (!nums.empty()) {
        prefixSums[0] = nums[0];
        for (size_t i = 1; i < nums.size(); ++i) {
            prefixSums[i] = prefixSums[i - 1] + nums[i];
        }
    }
    return prefixSums;
}

int count_common_elements(const vector<int>& sums1, const vector<int>& sums2) {
    // Sort both vectors first (not needed if they
    // are guaranteed to be sorted after sum calculation)
    vector<int> sorted1 = sums1, sorted2 = sums2;
    sort(sorted1.begin(), sorted1.end());
    sort(sorted2.begin(), sorted2.end());

    int count = 0;
    size_t i = 0, j = 0;
    while (i < sorted1.size() && j < sorted2.size()) {
        if (sorted1[i] == sorted2[j]) {
            count++;
            i++;
            j++;
        } else if (sorted1[i] < sorted2[j]) {
            i++;
        } else {
            j++;
        }
    }
    return count;
}

