        // Copyright Andrei-Gabriel Radu 321CAb 2023-2024
#include <bits/stdc++.h>

using namespace std;

/*
 * @brief Read input data from file.
 *
 * This function reads input data from the file "compresie.in".
 *
 * @param first_length - reference to store the length of the first sequence
 * @param second_length - reference to store the length of the second sequence
 * @param first_seq - vector to store the values of the first sequence
 * @param second_seq - vector to store the values of the second sequence
 */
void read_data(int& first_length, int& second_length,
				vector<long long>& first_seq, vector<long long>& second_seq) {
	// Open input file
	ifstream in("compresie.in");

	// Check if file is opened successfully
	if (!in) {
		cerr << "Could not open file";
		exit(-1);
	}

	// Read first sequence length and resize vector
	in >> first_length;
	first_seq.resize(first_length + 1);

	// Read first sequence values
	for (int i = 1; i <= first_length; i++)
		in >> first_seq[i];

	// Read second sequence length and resize vector
	in >> second_length;
	second_seq.resize(second_length + 1);

	// Read second sequence values
	for (int i = 1; i <= second_length; i++)
		in >> second_seq[i];

	// Close input file
	in.close();
}

/*
 * @brief Solve the problem and return the maximum length of
 * common subsequences.
 *
 * This function iterates through both sequences and finds
 * common subsequences.
 *
 * @param first_length - the length of the first sequence
 * @param second_length - the length of the second sequence
 * @param first_seq - vector containing the values of the first
 * sequence
 * @param second_seq - vector containing the values of the second
 * sequence
 * @return the maximum length of common subsequences
 */
int solve(int first_length, int second_length,
			vector<long long>& first_seq, vector<long long>& second_seq) {
	int max_length = 0, first_iter = 1, second_iter = 1;

	long long curr_val_first = first_seq[first_iter];
	long long curr_val_second = second_seq[second_iter];

	// Iterate through both sequences and find common subsequences
	while (first_iter <= first_length && second_iter <= second_length) {
		if (curr_val_first == curr_val_second) {
			// Increment max_length if values are equal
			max_length++;

			// Move to next element in first sequence
			first_iter++;
			// Move to next element in second sequence
			second_iter++;

			// Update current values for both sequences
			curr_val_first = first_seq[first_iter];
			curr_val_second = second_seq[second_iter];
		} else if (curr_val_first < curr_val_second) {
			// Move to next element in first sequence
			first_iter++;

			// Add the value to the current value for the first sequence
			curr_val_first += first_seq[first_iter];
		} else {
			// Move to next element in second sequence
			second_iter++;

			// Add the value to the current value for the second sequence
			curr_val_second += second_seq[second_iter];
		}
	}

	// If any of the sequences was not fully iterated through
	if (first_iter != (first_length + 1) || second_iter != (second_length + 1))
		return 0;

	// Return the maximum length of common subsequences
	return max_length;
}

/*
 * @brief Write the output to a file.
 *
 * This function writes the output data to the
 * file "compresie.out".
 *
 * @param max_length - the maximum length of common subsequences
 */
void print_output(int max_length) {
	// Open output file
	ofstream out("compresie.out");

	// If max_length is 0 or any of the sequences
	// was not fully iterated through, write -1 to file
	if (max_length == 0)
		out << -1;
	else
		// Otherwise, write max_length to file
		out << max_length;

	// Close output file
	out.close();
}

int main() {
	// Declare variables for sequence lengths
	int first_length, second_length;
	// Declare vectors for sequences
	vector<long long> first_seq, second_seq;

	// Read input data
	read_data(first_length, second_length, first_seq, second_seq);

	// Solve the problem and write the output
	print_output(solve(first_length, second_length, first_seq, second_seq));

	return 0;
}

