using namespace std;

// Compresses two vectors
int compress(vector<int>& v1, vector<int>& v2) {
    int i1 = 0, i2 = 0, l1 = v1.size(), l2 = v2.size(), l = 0;

    while (i1 < l1 && i2 < l2) {
        if (v1[i1] > v2[i2]) {
            // Sum the current element with the next from v2 until
            // is greater or equal to the element in v1
            while (v1[i1] > v2[i2] && i2 + 1 < l2) {
                v2[i2 + 1] += v2[i2];
                i2++;
            }
        } else if (v1[i1] < v2[i2]) {
            // Sum the current element with the next from v1 until
            // is greater or equal to the element in v2
            while (v1[i1] < v2[i2] && i1 + 1 < l1) {
                v1[i1 + 1] += v1[i1];
                i1++;
            }
        } else {
            // If the elements are equal, advance in both vectors
            // and increase final length
            l++;
            i1++;
            i2++;
        }
    }
    return l;
}

// Returns sum of elements in the vector
long long sum(vector<int>& v) {
    long long s = 0;

    for (auto &i : v)
        s += i;

    return s;
}

int main() {
    ifstream fin("compresie.in");
    ofstream fout("compresie.out");

    int l1, l2, result = 0;
    fin >> l1;
    vector<int> v1(l1, 0);
    for (auto &&i : v1)
        fin >> i;

    fin >> l2;
    vector<int> v2(l2, 0);
    for (auto &&i : v2)
        fin >> i;

    // If the sum of the elements are not equal,
    // the vectors can't be compressed to the same length
    if (sum(v1) != sum(v2))
        result = -1;
    else
        result = compress(v1, v2);

    fout << result << "\n";
    return 0;
}

