import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Compresie {
	static final int MOD = 1000000007;
	static int n;
	static int m;
	static int[] a;
	static int[] b;
	static List<Integer> c = new ArrayList<>();

	static void read_input() throws FileNotFoundException {
		Scanner input = new Scanner(new File("compresie.in"));
		n = input.nextInt();
		a = new int[n];
		for (int i = 0; i < n; i++) {
			a[i] = input.nextInt();
		}

		m = input.nextInt();
		b = new int[m];
		for (int i = 0; i < m; i++) {
			b[i] = input.nextInt();
		}
	}

	static int solve() {
		int i = 0, j = 0, sumA, sumB;
		while (i < n && j < m) {
			sumA = a[i];
			sumB = b[j];
			i++;
			j++;
			while (sumA != sumB) {
				while (sumA < sumB && i < n) {
					sumA += a[i];
					i++;
				}
				while (sumB < sumA && j < m) {
					sumB += b[j];
					j++;
				}
				if ((j == m && i == n) && sumB != sumA) {
					return -1;
				}
				if (sumA == sumB && ((i == n && j != m) || (i != n && j == m))) {
					return -1;
				}
			}
			c.add(sumA);
		}
		return c.size();
	}

	static void print_output() throws IOException {
		FileWriter myWriter = new FileWriter("compresie.out");
		myWriter.write(String.format("%d", solve()));
		myWriter.close();
	}

	public static void main(String[] args) throws IOException {
		read_input();
		print_output();
	}
}
