using namespace std;

// Function that calculates the maximum length possible for the password
// where the given character appears more than length / 2
int dynamic_find_for_one_character(vector<string> &words, int N,
                                    int len_max, char chr) {
    vector<vector<int>> dp(N + 1, vector<int>(len_max + 1, 0));

    for (int i = 1; i <= N; i++) {
        // we find the number of occurences of the chr
        // in the current word
        int occurences_chr = 0;
        for (auto chr_word : words[i - 1]) {
            if (chr_word == chr) {
                occurences_chr++;
            }
        }
        // we parse through each possible length
        for (int length = 0; length <= len_max; length++) {
            // we initiate the current best with the last best
            // (without including the current word)
            dp[i][length] = dp[i-1][length];

            size_t size_word = words[i - 1].length();

            // if the word can be added (the total length is >= word size)
            // we check if (length - size_word) password is possible
            // so we can add the current word
            if (length == size_word || (length > size_word
                && dp[i-1][length - size_word] != 0)) {
                int sol_aux = dp[i-1][length - size_word] + occurences_chr;
                // we get the maximum between with/without the current word
                dp[i][length] = max(dp[i][length], sol_aux);
            }
        }
    }

    // after we constructed the matrix we parse the last row
    // that consists of all possible lengths possible using all words
    // and we get the biggest password that respects our criteria
    for (int i = len_max; i >= 0; i--) {
        if (i < (2 * dp[N][i])) {
            return i;
        }
    }

    return 0;
}

// Comparator that compares two pairs descending after the second field
bool comparePairsDescendingInt(const pair<char, int>& p1,
                                const pair<char, int>& p2) {
    return p1.second > p2.second;
}

int main() {
    int N;
    // maximum password length possible
    // (sum sizes of all words)
    int len_max = 0;
    // holds the total frequency of each character
    // in the file
    map<char, int> freq_charac;
    // final result
    int result = 0;

    ifstream fin("criptat.in");
    ofstream fout("criptat.out");

    fin >> N;
    // words
    vector<string> words(N);

    for (int i = 0; i < N; i++) {
        string tmp;
        fin >> tmp;

        // we add each character to the frequency
        words[i] = tmp;
        for (auto chr : words[i]) {
            freq_charac[chr] += 1;
        }

        // and the length of the word len_max
        len_max += words[i].length();
    }

    // we want to sort the frequencies desceding so
    // we convert the map in a vector of pairs
    vector<pair<char, int>> freq_charac2(freq_charac.begin(),
                                            freq_charac.end());

    // we sort the vector using a custom comparator
    sort(freq_charac2.begin(), freq_charac2.end(), comparePairsDescendingInt);

    // for each character we find out the biggest password we can obtain
    // also respecting the rules
