		}

		for (int i = 0; i < alphabetLength; i++) {
			for (int j = 0; j < n; j++) {
				for (int k = 0; k < words[j].length(); k++) {
					char letter = words[j].charAt(k);

					if (alphabet[i] == letter) {
						certainLetterCount[i][j]++;
					}
				}
			}
