/// Aplică o promoție de 2 produse (50% reducere la cel mai ieftin).
/// @param prod1 prețul primului produs
/// @param prod2 prețul celui de-al doilea produs
/// @return prețul rezultat în urma aplicării promoției
double offer_of_2(double prod1, double prod2) {
    return std::max(prod1, prod2) + (std::min(prod1, prod2) / 2);
}

/// Aplică o promoție de 3 produse (gratuitate la cel mai ieftin).
/// @param prod1 prețul primului produs
/// @param prod2 prețul celui de-al doilea produs
/// @param prod3 prețul celui de-al treilea produs
/// @return prețul rezultat în urma aplicării promoției
double offer_of_3(double prod1, double prod2, double prod3) {
    return prod1 + prod2 + prod3 - std::min({prod1, prod2, prod3});
}

/// Adaugă la elementele dintr-un vector un anume număr.
/// @param v vectorul de bază
/// @param to_add numărul de adăugat
/// @return un nou vector cu elementele actualizate
std::vector<double> add_with(const std::vector<double> &v, double to_add) {
    std::vector<double> result = v;
    for (double &el : result) {
        el += to_add;
    }

    return result;
}

/// Unește 2 vectori sortați crescător, cu indexare de la 0
/// într-unul asemenea, fără elemente duplicate, de o lungime maximă.
/// @param v1 primul vector de unit
/// @param v2 al doilea vector de unit
/// @param max_len lungimea maximă a rezultatului
/// @return vectorul unit
std::vector<double> merge(const std::vector<double> &v1,
                          const std::vector<double> &v2,
                          unsigned long max_len) {
    std::vector<double> result;
    unsigned long cursor1 = 0, cursor2 = 0;

    while (result.size() < max_len
           && (cursor1 < v1.size() || cursor2 < v2.size())) {
        if (cursor1 == v1.size()) {
            result.push_back(v2[cursor2]);
            cursor2++;
            continue;
        }
        if (cursor2 == v2.size()) {
            result.push_back(v1[cursor1]);
            cursor1++;
            continue;
        }

        if (v1[cursor1] < v2[cursor2]) {
            result.push_back(v1[cursor1]);
            cursor1++;
        } else if (v1[cursor1] == v2[cursor2]) {
            cursor2++;
        } else {
            result.push_back(v2[cursor2]);
            cursor2++;
        }
    }

    return result;
}

