// Used for three-way merge_into when one vector is left
static void merge_into(
    std::vector<double>& result,
    size_t count,
    const std::vector<double>& in,
    size_t& index
) {
    size_t size = in.size();
    while (index < size) {
        if (result.size() == count)
            return;

        result.push_back(in[index]);
        index++;
    }
}

// Used for three-way merge_into when two vectors are left
static void merge_into(
    std::vector<double>& result,
    size_t count,
    const std::vector<double>& in1,
    const std::vector<double>& in2,
    size_t& index1,
    size_t& index2
) {
    size_t size1 = in1.size();
    size_t size2 = in2.size();
    while (index1 < size1 && index2 < size2) {
        if (result.size() == count)
            return;

        auto& elem1 = in1[index1];
        auto& elem2 = in2[index2];

        if (elem1 < elem2) {
            result.push_back(elem1);
            index1++;
        } else {
            result.push_back(elem2);
            index2++;
            if (elem1 == elem2)
                index1++;
        }
    }
}

// Three-way merge algorithm that stops after merging a certain amount of
// elements
static void merge_into(
    std::vector<double>& result,
    size_t count,
    const std::vector<double>& in1,
    const std::vector<double>& in2,
    const std::vector<double>& in3
) {
    size_t size1 = in1.size();
    size_t size2 = in2.size();
    size_t size3 = in3.size();

    size_t index1 = 0;
    size_t index2 = 0;
    size_t index3 = 0;

    result.clear();

    // Merge all 3 vectors until one of them runs out
    while (index1 < size1 && index2 < size2 && index3 < size3) {
        if (result.size() == count)
            return;

        auto& elem1 = in1[index1];
        auto& elem2 = in2[index2];
        auto& elem3 = in3[index3];

        if (elem1 < elem2) {
            if (elem1 < elem3) {
                result.push_back(elem1);
                index1++;
                continue;
            }
            if (elem1 == elem3)
                index1++;
        } else {
            if (elem1 == elem2)
                index1++;
            if (elem2 < elem3) {
                result.push_back(elem2);
                index2++;
                continue;
            }
            if (elem2 == elem3)
                index2++;
        }
        result.push_back(elem3);
        index3++;
    }

    // Merge pairs of two vectors
    merge_into(result, count, in1, in2, index1, index2);
    merge_into(result, count, in1, in3, index1, index3);
    merge_into(result, count, in2, in3, index2, index3);

    // Add remaining elements from the last vectors
    merge_into(result, count, in1, index1);
    merge_into(result, count, in2, index2);
    merge_into(result, count, in3, index3);
