double power(double cost, int N, const vector<int>& P, const vector<int>& C) {
    double min_pow = 1000000000;
    for (int i = 0; i < N; i++) {
        double current = P[i] - abs(C[i] - cost);
        if (current < min_pow) {
            min_pow = current;
        }
    }
    return min_pow;
}

double best(double lower, double upper, int N,
