public class Servere {
	static class Task {
		public final String Input = "servere.in";
		public final String Output = "servere.out";

		int n;
		int[] Powers;
		int[] Limits;

		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private void readInput() {
			try {
				Scanner sc = new Scanner(new File(Input));
				n = sc.nextInt();
				Powers = new int[n + 1];
				Limits = new int[n + 1];
				for (int i = 0; i < n; i++) {
					Powers[i] = sc.nextInt();
				}		 
				for (int i = 0; i < n; i++) {
					Limits[i] = sc.nextInt();
				}	   
				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(double result) {
			try {
				PrintWriter pw = new PrintWriter(new File(Output));
				pw.printf("%f\n", result);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private double getResult() {
			int[] Sums = new int[n];
			int[] Diffs = new int[n];
			for (int i = 0; i < n; i++) {
				Sums[i] = Powers[i] + Limits[i];
				Diffs[i] = Powers[i] - Limits[i];
			}
			Arrays.sort(Sums);
			Arrays.sort(Diffs);
			return ((double)(Sums[0] + Diffs[0])) / 2;

		}

	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

