        import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.util.Scanner;

public class Servere {
	static int n;
	static int[] p;
	static int[] c;
	static double final_crt;

	static void read_input() throws FileNotFoundException {
		Scanner input = new Scanner(new File("servere.in"));
		n = input.nextInt();
		p = new int[n];
		c = new int[n];
		for (int i = 0; i < n; i++) {
			p[i] = input.nextInt();
		}

		for (int i = 0; i < n; i++) {
			c[i] = input.nextInt();
		}
	}

	static double calcMinPower(double mid) {
		double min = Integer.MAX_VALUE;
		for (int j = 0; j < n; j++) {
			if (p[j] - Math.abs(mid - c[j]) < min) {
				min = p[j] - Math.abs(mid - c[j]);
			}
		}
		return min;
	}

	static void solve() {
		double left = 0.0, right = Integer.MAX_VALUE, mid;
		while (left <= right) {
			mid = (left + right) / 2.0;
			double center = calcMinPower(mid);
			double lCenter = calcMinPower(mid - 0.1);
			double rCenter = calcMinPower(mid + 0.1);
			if (center > lCenter && center > rCenter) {
				final_crt = center;
				return;
			} else if (lCenter < rCenter) {
				left = mid + 0.1;
			} else {
				right = mid - 0.1;
			}
		}
	}

	static void print_output() throws IOException {
		FileWriter myWriter = new FileWriter("servere.out");
		myWriter.write(String.format("%.1f", final_crt));
		myWriter.close();
