			Calculator[] calculatoare = new Calculator[N];
			//citire putere
			for (int i = 0; i < N; i++) {
				calculatoare[i] = new Calculator();
				calculatoare[i].putere = scanner.nextInt();
			}
			//citire curent si calcularea puterii
			for (int i = 0; i < N; i++) {
				calculatoare[i].curent = scanner.nextInt();
				if (i >= 1) {
					calculatoare[0] = putereMaxima(calculatoare[0], calculatoare[i]);
				}
			}
			scanner.close();

			FileWriter writer = new FileWriter("servere.out");
			writer.write(String.format("%.1f", calculatoare[0].putere));
			writer.close();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
	private static Calculator putereMaxima(Calculator calculator1, Calculator calculator2) {
		//inversez cele 2 calculatoare pentru ca primul sa aiba curent mai mic
		if (calculator1.curent > calculator2.curent) {
			Calculator aux = calculator1;
			calculator1 = calculator2;
			calculator2 = aux;
		}
		double st = calculator1.curent;
		double dr = calculator2.curent;
		double maxPower = Double.NEGATIVE_INFINITY;
		double curentOpt = 0.0d;
		//cautare binara in intervalul de curenti
		while (st <= dr) {
			if (st == dr) {
				double powerMid1 = calculator1.putere - Math.abs(dr - calculator1.curent);
				double powerMid2 = calculator2.putere - Math.abs(dr - calculator2.curent);
				double minMid = Math.min(powerMid1,powerMid2);
				maxPower = minMid;
				curentOpt = dr;
				break;
			}
			double curent = (st + dr) / 2;
			if (curent - Math.floor(curent) < 0.5) {
				curent = Math.floor(curent);
			} else if (curent - Math.floor(curent) > 0.5) {
				curent = Math.floor(curent) + 0.5;
			}
			//calculez puterea pentru curentul la care am ajuns
			double powerMid1 = calculator1.putere - Math.abs(curent - calculator1.curent);
			double powerMid2 = calculator2.putere - Math.abs(curent - calculator2.curent);
			double minMid = Math.min(powerMid1,powerMid2);
			if (minMid > maxPower) {
				maxPower = minMid;
				curentOpt = curent;
			}
			//cu ok verific daca gasesc in stanga sau in dreapta o putere mai mare
			boolean ok = false;
			//verific daca in stanga sau in dreapta este puterea mai mare
			//si modific contorii st si dr corespunzator
			double powerSt1 = calculator1.putere - Math.abs((curent - 0.5) - calculator1.curent);
			double powerSt2 = calculator2.putere - Math.abs((curent - 0.5) - calculator2.curent);
			double minSt = Math.min(powerSt1,powerSt2);
			if (minSt > minMid) {
				maxPower = minSt;
				dr = curent - 0.5;
				curentOpt = curent - 0.5;
				ok = true;
			}
			double powerDr1 = calculator1.putere - Math.abs((curent + 0.5) - calculator1.curent);
			double powerDr2 = calculator2.putere - Math.abs((curent + 0.5) - calculator2.curent);
			double minDr = Math.min(powerDr1,powerDr2);
			if (minDr > minMid) {
				maxPower = minDr;
				st = curent + 0.5;
				curentOpt = curent + 0.5;
				ok = true;
			}
			//daca ok e inca fals inseamna ca am ajuns la puterea maxima
			if (!ok) {
				break;
			}
		}
		return new Calculator(maxPower, curentOpt);
	}
}
