using namespace std;

double gasire_putere(double mid, long *putere, long *curent, long n) {
    double rezultat = 1000000000, formula;
    for (int i = 0; i < n; i++) {
        formula = putere[i] - abs(mid - curent[i]);
        if (formula < rezultat) {
            rezultat = formula;
        }
    }
    return rezultat;
}

int main() {
    ifstream fisier_in("servere.in");
    ofstream fisier_out("servere.out");

    long n, x, max_curent = -1, putere_minima = 1000000000;
    double left, right, mid, rezultat;
    long *putere, *curent;

    fisier_in >> n;
    putere = (long *)malloc(n * sizeof(long));
    curent = (long *)malloc(n * sizeof(long));

    for (int i = 0; i < n; i++) {
        fisier_in >> x;
        putere[i] = x;
        if (x < putere_minima) {
            putere_minima = x;
        }
    }

    for (int i = 0; i < n; i++) {
        fisier_in >> x;
        curent[i] = x;
        if (max_curent < x) {
            max_curent = x;
        }
    }

    left = 0;
    right = max_curent;
    rezultat = 0;

    while (left < right) {
        mid = (left + right) / 2;
        double putere_stanga, putere_dreapta;
        putere_stanga = gasire_putere((mid + left) / 2, putere, curent, n);
        putere_dreapta = gasire_putere((mid + right) / 2, putere, curent, n);
        if (putere_stanga <= putere_dreapta) {
            rezultat = putere_dreapta;
            left = mid + 0.001;
        } else {
            rezultat = gasire_putere(mid, putere, curent, n);
            right = mid - 0.001;
        }
    }
    fisier_out << fixed << setprecision(1) << rezultat << "\n";
}

