#include <fstream>
#include <vector>
#include <algorithm>
#include <list>
#include <queue>
#include <map>
#include <set>

using namespace std;

void dijkstra(int start, vector<vector<pair<int, unsigned long long>>> &graph,
    vector<unsigned long long> &distances) {
    int n = graph.size();
    distances.assign(n, INT64_MAX);
    distances[start] = 0;

    set<pair<unsigned long long, int>> active_vertices;
    active_vertices.insert({ 0, start });

    while (!active_vertices.empty()) {
        auto current = *active_vertices.begin();
        active_vertices.erase(active_vertices.begin());

        unsigned long long current_distance = current.first;
        int current_node = current.second;

        for (const auto &neighbor : graph[current_node]) {
            int next_node = neighbor.first;
            unsigned long long weight = neighbor.second;

            if (current_distance + weight < distances[next_node]) {
                active_vertices.erase({ distances[next_node], next_node });

                distances[next_node] = current_distance + weight;
                active_vertices.insert({ distances[next_node], next_node });
            }
        }
    }
}

int main(void) {
    int n, m, x, y, z;
    ifstream in("drumuri.in");
    ofstream out("drumuri.out");
    in >> n >> m;
    vector<vector<pair<int, unsigned long long>>> graph(n + 1);
    vector<vector<pair<int, unsigned long long>>> transpose(n + 1);

    for (int i = 0; i < m; i++) {
        unsigned long long cost;
        int  node, neigh;
        in >> node >> neigh >> cost;
        graph[node].push_back({ neigh, cost });
        transpose[neigh].push_back({ node, cost });
    }

    in >> x >> y >> z;

    vector<unsigned long long> distances_from_x;
    vector<unsigned long long> distances_from_y;
    vector<unsigned long long> distances_from_z;

    dijkstra(x, graph, distances_from_x);
    dijkstra(y, graph, distances_from_y);
    dijkstra(z, transpose, distances_from_z);

    uint64_t minim = UINT64_MAX;
    for (int i = 1; i <= n; i++) {
        if (distances_from_x[i] == INT64_MAX ||
            distances_from_y[i] == INT64_MAX ||
            distances_from_z[i] == INT64_MAX) {
            continue;
        }

        uint64_t sum =
            distances_from_x[i] +
            distances_from_y[i] +
            distances_from_z[i];

        if (sum < minim) {
            minim = sum;
        }
    }
    out << minim;

    return 0;
}

