import java.util.Scanner;

public class Drumuri {
	static class Task {
		public static final String INPUT_FILE = "drumuri.in";
		public static final String OUTPUT_FILE = "drumuri.out";

		int N, M;
		int x, y, z;
		List<Edge>[] adj;
		List<Edge>[] reversed;

		static class Edge {
			int node;
			int cost;
			Edge(int node, int cost) {
				this.node = node;
				this.cost = cost;
			}
		}

		public void solve() {
			readInput();
			long result = getResult();
			writeOutput(result);
		}

		// Citeste datele de intrare
		private void readInput() {
			try {
				Scanner sc = new Scanner(new BufferedReader(new FileReader(INPUT_FILE)));
				N = sc.nextInt();
				M = sc.nextInt();

				adj = new ArrayList[N + 1];
				reversed = new ArrayList[N + 1];
				for (int node = 1; node <= N; node++) {
					adj[node] = new ArrayList<>();
					reversed[node] = new ArrayList<>();
				}

				for (int i = 0; i < M; i++) {
					int a = sc.nextInt();
					int b = sc.nextInt();
					int c = sc.nextInt();
					adj[a].add(new Edge(b, c));
					reversed[b].add(new Edge(a, c));
				}

				x = sc.nextInt();
				y = sc.nextInt();
				z = sc.nextInt();

				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		// Scrie rezultatul in fisierul de iesire
		private void writeOutput(long result) {
			try {
				PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(OUTPUT_FILE)));
				pw.printf("%d", result);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private long getResult() {
			long[] distX = dijkstra(x, adj);
			long[] distY = dijkstra(y, adj);
			long[] distZ =  dijkstra(z, reversed);
			long dist = distX[z] + distY[z];
			for (int node = 1; node <= N; node++) {
				if (distX[node] != -1 && distY[node] != -1 && distZ[node] != -1) {
					long new_dist = distX[node] + distY[node] + distZ[node];
					if (new_dist < dist) {
						dist = new_dist;
					}
				}
			}
			return dist;
		}

		private long[] dijkstra(int start, List<Edge>[] adj) {
			PriorityQueue<Edge> pq = new PriorityQueue<>(Comparator.comparingLong(e -> e.cost));
			long[] dist = new long[N + 1];
			Arrays.fill(dist, Long.MAX_VALUE);
			dist[start] = 0;
			pq.add(new Edge(start, 0));
			while (!pq.isEmpty()) {
				Edge current = pq.poll();
				int u = current.node;
				long d = current.cost;
				if (d > dist[u]) {
					continue;
				}
				for (Edge e : adj[u]) {
					int v = e.node;
					long newDist = dist[u] + e.cost;
					if (newDist < dist[v]) {
						dist[v] = newDist;
						pq.add(new Edge(v, (int) newDist));
					}
				}
			}
			for (int i = 0; i <= N; i++) {
				if (dist[i] == Long.MAX_VALUE) {
					dist[i] = -1;
				}
			}
			return dist;
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}

