using namespace std;


ifstream fin("drumuri.in");
ofstream fout("drumuri.out");


// Type for representing a weighted edge: first is node, second is weight
typedef pair<long long, int> pii;
// Type for representing large integers
typedef long long ll;
// Infinite distance value
const ll INF = 2000000000000;

// distances vector
vector<ll> dist;
// Adjacency lists for graph and its reverse
vector<vector<pii>> adj, reverseAdj;

// Dijkstra's algorithm to find shortest paths from a start node
vector<ll> dijkstra(int start, const vector<vector<pii>>& adj) {
    dist.resize(adj.size());
    dist.assign(adj.size(), INF);
    // Priority queue to select node with minimum distance
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    // Push start node with distance 0
    pq.push({0, start});
    // Initialize distance of start node
    dist[start] = 0;

    // Continue until priority queue is empty
    while (!pq.empty()) {
        // Get node with minimum distance
        long long cost = pq.top().first;
        int node = pq.top().second;
        pq.pop();

        // Traverse edges connected to the current node
        for (const auto &edge : adj[node]) {
            int nextNode = edge.first;
            int nextCost = edge.second;
            // Update distance if a shorter path is found
            if (dist[nextNode] > dist[node] + nextCost) {
                dist[nextNode] = dist[node] + nextCost;
                // Push updated distance and node to priority queue
                pq.push({dist[nextNode], nextNode});
            }
        }
    }

    return dist;
}

// Main function to read input, run Dijkstra's algorithm, and write output
int main() {
    // Number of nodes and edges
    int N, M;
    fin >> N >> M;

    // Read edges and populate adjacency lists
    adj.resize(N + 1);
    reverseAdj.resize(N + 1);

    for (int i = 0; i < M; ++i) {
        int a, b, c;
        fin >> a >> b >> c;
        adj[a].push_back({b, c});
        reverseAdj[b].push_back({a, c});
    }

    // Nodes x, y, and z
    int x, y, z;
    fin >> x >> y >> z;

    // fout << "pula mea" << endl;
    // Run Dijkstra's algorithm from x, y, and z
    vector<ll> distFromX = dijkstra(x, adj);
    vector<ll> distFromY = dijkstra(y, adj);
    vector<ll> distToZ = dijkstra(z, reverseAdj);

    // fout << "pula mea" << endl;

    // Find the minimum cost from x to z and y to z via any common node
    ll minCost = INF;
    for (int i = 1; i <= N; ++i) {
        if (distFromX[i] != INF && distFromY[i] != INF && distToZ[i] != INF) {
            long long minimum_cost = distFromX[i] + distFromY[i] + distToZ[i];
            minCost = min(minCost, minimum_cost);
        }
    }

    // Write minimum cost to output file
    if (minCost == INF) {
        fout << -1 << endl;
    } else {
        fout << minCost << endl;
    }

    return 0;
}

