using namespace std;

struct Edge {
    int destination;
    long long weight;

    Edge(int dest, long long w) : destination(dest), weight(w) {}
};


vector<long long> dijkstra(int start, const vector<vector<Edge>>& graph,
                    const vector<vector<long long>>& weights, int N) {
    vector<long long> dist(N + 1, LLONG_MAX);
    vector<bool> visited(N + 1, false);
    dist[start] = 0;

    priority_queue<pair<long long, int>, vector<pair<long long, int>>,
                                    greater<pair<long long, int>>> pq;
    pq.push({0, start});

    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();

        if (visited[u]) continue;
        visited[u] = true;

        for (size_t i = 0; i < graph[u].size(); ++i) {
            int v = graph[u][i].destination;
            long long weight = weights[u][i];
            if (!visited[v] && dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }

    return dist;
}

