    ifstream fin("drumuri.in");
    fin >> n >> m;

    // adj1 este matricea de adiacenta
    // adj2 este matricea de adiacenta transpusa
    for (int i = 1, a, b, w; i <= m; i++) {
        fin >> a >> b >> w;
        adj1[a].push_back({b, w});
        adj2[b].push_back({a, w});
    }
    fin >> x >> y >> z;
    fin.close();
