        // Lab 8

#include <bits/stdc++.h>
using namespace std;

const long long NMAX = 50005;
long long INF = LLONG_MAX;

struct DijkstraResult {
    vector<long long> d;
    vector<long long> p;

    DijkstraResult(const vector<long long>& d,
                    const vector<long long>& p)
        : d(d)
        , p(p) { }
};

class Task {
 public:
    void solve() {
        read_input();
        print_output(get_result());
    }

 private:
    long long n, m;
    long long x, y, z;
    vector<vector<pair<long long, long long>>> adj;
    vector<vector<pair<long long, long long>>> adj2;

    /**
     * Start of the part that was modified
     * 
     * We read the input
    */
    void read_input() {
        ifstream fin("drumuri.in");
        fin >> n >> m;
        adj.resize(n + 1);
        adj2.resize(n + 1);

        for (long long i = 0; i < m; i++) {
            long long a, b;
            long long c;
            fin >> a >> b >> c;
            /**
             * We get the normal graph
            */
            adj[a].push_back({b, c});

            /**
             * We get the transposed graph to get the distance from
             * z to another node k for example and to check if x and y
             * are connected to k in some way and we need to
             * go like x -> k -> z and y -> k -> z.
             *
             * If we didn't check for a node like this, we could overlap in
             * some cases
            */
            adj2[b].push_back({a, c});
        }

        fin >> x >> y >> z;
        fin.close();
    }

    /**
     * Dijkstra's algorithm
    */
    DijkstraResult dijkstra(long long src,
                        vector<vector<pair<long long, long long>>> &graph) {
        vector<long long> dist(n + 1, INF);
        vector<long long> parent(n + 1, -1);
        priority_queue<pair<long long, long long>,
                        vector<pair<long long, long long>>,
                            greater<pair<long long,
                                            long long>>> pq;

        dist[src] = 0;
        pq.push({0, src});

        while (!pq.empty()) {
            auto [d, u] = pq.top();
            pq.pop();

            /**
             * To be more efficient, we skip the node if we already
             * found a shorter path to it
            */
            if (d != dist[u]) {
                continue;
            }

            for (const auto& e : graph[u]) {
                 long long v = e.first;
                 long long cost = e.second;
                if (dist[u] + cost < dist[v]) {
                    dist[v] = dist[u] + cost;
                    parent[v] = u;
                    pq.push({dist[v], v});
                }
            }
        }

        return DijkstraResult(dist, parent);
    }

    /**
     * Here we will calculate the path to z from x and y
     * and then we will return the sum of the two paths
     * 
     * O((n + m) * log(n))
    */
     long long get_result() {
        DijkstraResult dij_x = dijkstra(x, adj);
        DijkstraResult dij_y = dijkstra(y, adj);
        /**
         * We need to get to the distance from z to a node k
        */
        DijkstraResult dij_z = dijkstra(z, adj2);

        long long result = INF;

        /**
         * We will need to get to a node k
         * 
         * We could get the case:
         * x y
         * \/
         * k
         * |
         * z
         * 
         * So we need to check if that case overlaps, that's why we will
         * get 32/40 tests when we implement only dijkstra from x and y
         * to z
        */
        for (long long i = 1; i <= n; i++) {
            if (dij_x.d[i] != INF && dij_y.d[i] != INF && dij_z.d[i] != INF) {
                result = min(result, dij_x.d[i] + dij_y.d[i] + dij_z.d[i]);
            }
        }

        if (result == INF)
            return -1;
        else
            return result;
    }

    /**
     * Here we put the result in the output file
    */
    void print_output(long long result) {
        ofstream fout("drumuri.out");
        fout << result << endl;
    }
    /**
     * The end of the part that was modified
    */
};

