        import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.StringTokenizer;

public class Numarare {
	public static final String INPUT_FILE = "numarare.in";
	public static final String OUTPUT_FILE = "numarare.out";
	public static final int MOD = 1000000007;

	// unde m = numarul de noduri, iar m = numarul de muchii
	int n, m;
	// lista de seturi pentru cele 2 grafuri, astfel incat nu avem duplicate
	List<Set<Integer>> graph1;
	List<Set<Integer>> graph2;

	public void solve() {
		readInput();
		writeOutput(getResult());
	}

	private void readInput() {
		try (BufferedReader br = new BufferedReader(new FileReader(INPUT_FILE))) {
			StringTokenizer st = new StringTokenizer(br.readLine());
			n = Integer.parseInt(st.nextToken());
			m = Integer.parseInt(st.nextToken());

			// initializam cele 2 grafuri ca liste goale
			graph1 = new ArrayList<>(n);
			graph2 = new ArrayList<>(n);

			// adaugam cate un set gol pentru fiecare nod
			for (int i = 0; i < n; i++) {
				graph1.add(new HashSet<>());
				graph2.add(new HashSet<>());
			}

			for (int i = 0; i < m; i++) {
				st = new StringTokenizer(br.readLine());
				int x = Integer.parseInt(st.nextToken()) - 1;
				int y = Integer.parseInt(st.nextToken()) - 1;
				// adaugam o muchie de la x la y in primul graf
				graph1.get(x).add(y);
			}

			for (int i = 0; i < m; i++) {
				st = new StringTokenizer(br.readLine());
				int x = Integer.parseInt(st.nextToken()) - 1;
				int y = Integer.parseInt(st.nextToken()) - 1;
				// adaugam o muchie de la x la y in al doilea graf
				graph2.get(x).add(y);
			}
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private void writeOutput(int result) {
		try (PrintWriter pw = new PrintWriter(new BufferedWriter(new FileWriter(OUTPUT_FILE)))) {
			pw.printf("%d\n", result);
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	private int getResult() {
		// stocam numarul de drumuri pentru fiecare nod
		int[] paths = new int[n];
		// initializam cu 1 numarul de drumuri pentru nodul de start
		paths[0] = 1;

		// iteram prin fiecare nod
		for (int i = 0; i < n; i++) {
			// pentru fiecare nod, iteram prin vecinii sai din graful 1
			for (int neighbor : graph1.get(i)) {
				if (graph2.get(i).contains(neighbor)) {
					// daca nodul curent are acelasi vecin in graful al doilea,
					// atunci actualizam numarul de drumuri catre vecin
					// adaugand numarul de drumuri catre nodul curent
					paths[neighbor] = (paths[neighbor] + paths[i]) % MOD;
				}
			}
		}

		// returnam numarul de drumuri catre nodul final
