        import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileWriter;
import java.io.IOException;
import java.io.Writer;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;
import java.util.Vector;

public class Curse {
	//https://www.geeksforgeeks.org/topological-sorting-indegree-based-solution/
	public static void topologicalSort(int V,
									ArrayList<ArrayList<Integer>> adj, ArrayList<Integer> answer) {
		int[] indegree = new int[V + 1];
		for (int i = 0; i < V; i++) {
			ArrayList<Integer> temp = adj.get(i);
			for (int node : temp) {
				indegree[node]++;
			}
		}
		Queue<Integer> q = new LinkedList();
		for (int i = 0; i < V; i++) {
			if (indegree[i] == 0) {
				q.add(i);
			}
		}
		int cnt = 0;
		Vector<Integer> topOrder = new Vector<Integer>();
		while (!q.isEmpty()) {
			int u = q.poll();
			topOrder.add(u);

			for (int node : adj.get(u)) {
				if (--indegree[node] == 0) {
					q.add(node);
				}
			}
			cnt++;
		}
		if (cnt != V) {
			System.out.println("There exists a cycle in the graph");
			return;
		}
		for (int i : topOrder) {
			answer.add((i + 1));
		}
	}

	public static void main(String[] args) {
		try {
			File myObj = new File("curse.in");
			final String newLine = "\n";
			Writer outputFile = new FileWriter("curse.out");
			Scanner myReader = new Scanner(myObj);
			//nr de piste
			int p = myReader.nextInt();
			//nr masini
			int carsNo = myReader.nextInt();
			//nr antrenamente
			int a = myReader.nextInt();
			//matricea de piste aranjamente masini
			int[][] mat = new int[a][p];
			//un vector auxiliar ca sa tin cont de antrenamentele deja interogate
			int[] aux = new int[a];
			//initializam matricea de start
			for (int i = 0; i < a; i++) {
				for (int j = 0; j < p; j++) {
					mat[i][j] = myReader.nextInt();
				}
			}
			//vom initializa vectorul aux cu 0
			for (int i = 0; i < a; i++) {
				aux[i] = 0;
			}
			//graful meu pe care o sa il contruiesc pe baza a ce relatii
			//gasesc in matrice
			ArrayList<ArrayList<Integer>> adj = new ArrayList<>();
			//initializam graful
			for (int i = 0; i < carsNo; i++) {
				ArrayList<Integer> item = new ArrayList<Integer>();
				adj.add(item);
			}
			for (int i = 0; i < p; i++) {
				for (int j = 0; j < a - 1; j++) {
					//conditia mea de valid -> linia sa nu fi fost vizitata
					//cele doua masini sa fie diferite
					if (mat[j][i] != mat[j + 1][i] && (aux[j] != -1)) {
						//notam ca vizitata linia j
						aux[j] = -1;
						//adaugam relatia obtinuta in graf
						adj.get(mat[j][i] - 1).add(mat[j + 1][i] - 1);
					}
				}
			}
			//array-ul rezultat
			ArrayList<Integer> answer = new ArrayList<>();
			//sortam topologic graful, pe baza relatiilor din el
			topologicalSort(carsNo, adj, answer);
			//printam rezultatul
			for (Integer integer : answer) {
				outputFile.write(integer + " ");
			}
			outputFile.write(newLine);
			myReader.close();
			outputFile.close();
		} catch (FileNotFoundException e) {
			System.out.println("An error occurred.");
			e.printStackTrace();
		} catch (IOException e) {
			e.printStackTrace();
		}
	}
}

